async function detectPythonMissingBenchmarkEvaluatorDispatch(scriptPath?: string): Promise<string | undefined> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return undefined;
  }
  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return undefined;
  }

  const hasBaselineCandidateEvaluator =
    source.includes("No benchmark evaluator was defined by the evaluation_metrics_logic section") ||
    source.includes("No zero-shot benchmark evaluation function was defined in earlier sections") ||
    (source.includes("required helper missing; expected one of:") &&
      BENCHMARK_EVALUATOR_ENTRYPOINT_NAMES.some(
        (name) => source.includes(`"${name}"`) || source.includes(`'${name}'`)
      )) ||
    source.includes("evaluation_metrics_logic section") ||
    source.includes("_evaluate_candidate_for_run");
  if (!hasBaselineCandidateEvaluator) {
    return undefined;
  }

  const referencedEntrypoints = BENCHMARK_EVALUATOR_ENTRYPOINT_NAMES.filter(
    (name) => source.includes(`"${name}"`) || source.includes(`'${name}'`)
  );
  if (referencedEntrypoints.length === 0) {
    return undefined;
  }

  const definedEntrypoints = referencedEntrypoints.filter((name) =>
    pythonSourceDefinesName(source, name)
  );
  if (definedEntrypoints.length > 0) {
    return undefined;
  }

  const generatedEvaluatorNames = KNOWN_GENERATED_BENCHMARK_EVALUATOR_NAMES.filter((name) =>
    pythonSourceDefinesName(source, name)
  );
  const explicitMissingEvaluatorRuntimeError = source.includes(
    "No zero-shot benchmark evaluation function was defined in earlier sections"
  );
  if (generatedEvaluatorNames.length === 0 && !explicitMissingEvaluatorRuntimeError) {
    return undefined;
  }

  const visibleReferenced = referencedEntrypoints.join(", ");
  const visibleGenerated = generatedEvaluatorNames.slice(0, 6).join(", ") || "none";
  return [
    "Generated Python runner has a benchmark evaluator dispatch mismatch.",
    `Baseline-first candidate evaluation searches for undefined evaluator entrypoint(s): ${visibleReferenced}.`,
    `Generated evaluator function(s) exist under different name(s): ${visibleGenerated}.`,
    "Define one searched evaluator entrypoint, or align the candidate evaluator lookup with the generated benchmark evaluator before handoff."
  ].join(" ");
}

async function detectPythonBenchmarkLoaderDispatchMismatch(scriptPath?: string): Promise<string | undefined> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return undefined;
  }
  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return undefined;
  }

  const missingMarkerIndex = BENCHMARK_LOADER_MISSING_MARKERS.map((marker) => source.indexOf(marker)).find(
    (index) => index >= 0
  );
  if (missingMarkerIndex === undefined) {
    return undefined;
  }

  const resolverWindow = source.slice(
    Math.max(0, missingMarkerIndex - 1800),
    Math.min(source.length, missingMarkerIndex + 800)
  );
  const referencedLoaderNames = BENCHMARK_LOADER_ENTRYPOINT_NAMES.filter(
    (name) => resolverWindow.includes(`"${name}"`) || resolverWindow.includes(`'${name}'`)
  );
  if (referencedLoaderNames.length === 0) {
    return undefined;
  }

  const definedReferencedLoaders = referencedLoaderNames.filter((name) =>
    pythonSourceDefinesName(source, name)
  );
  if (definedReferencedLoaders.length > 0) {
    return undefined;
  }

  const generatedLoaderNames = BENCHMARK_LOADER_ENTRYPOINT_NAMES.filter((name) =>
    pythonSourceDefinesName(source, name)
  );
  if (generatedLoaderNames.length === 0) {
    return undefined;
  }

  const visibleReferenced = referencedLoaderNames.join(", ");
  const visibleGenerated = generatedLoaderNames.slice(0, 6).join(", ");
  return [
    "Generated Python runner has a benchmark loader dispatch mismatch.",
    `Benchmark evaluation searches for undefined loader helper(s): ${visibleReferenced}.`,
    `Generated loader helper(s) exist under different name(s): ${visibleGenerated}.`,
    "Define one searched benchmark loader helper, or align the evaluator loader lookup with the generated loader before handoff."
  ].join(" ");
}

async function detectPythonDeviceMetricsCallArityMismatch(scriptPath?: string): Promise<string | undefined> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return undefined;
  }
  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return undefined;
  }

  const signature = extractPythonFunctionSignature(source, "_collect_device_metrics");
  if (!signature) {
    return undefined;
  }
  const requiredParams = extractPythonRequiredParameterNames(signature);
  if (requiredParams.length === 0) {
    return undefined;
  }

  const callLines = source
    .split(/\r?\n/u)
    .map((line, index) => ({ line, lineNumber: index + 1 }))
    .filter(({ line }) => {
      const trimmed = line.trim();
      return !trimmed.startsWith("def ") && /\b_collect_device_metrics\s*\(\s*\)/u.test(line);
    });
  if (callLines.length === 0) {
    return undefined;
  }

  const visibleCalls = callLines
    .slice(0, 4)
    .map(({ lineNumber }) => `${path.basename(scriptPath)}:${lineNumber}`)
    .join(", ");
  return [
    "Generated Python runner has a device metrics helper call arity mismatch.",
    `_collect_device_metrics requires ${requiredParams.join(", ")} but is called with no arguments at ${visibleCalls}.`,
    "Pass the orchestration result, make the parameter optional with a safe default, or use a signature-aware adapter before handoff."
  ].join(" ");
}

async function detectPythonInvokeHelperDispatchMismatch(scriptPath?: string): Promise<string | undefined> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return undefined;
  }
  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return undefined;
  }

  if (!/\bdef\s+_invoke_helper\s*\(/u.test(source) || !/\b_invoke_helper\s*\(/u.test(source)) {
    return undefined;
  }

  const missingGroups: string[][] = [];
  for (const match of source.matchAll(/\b_invoke_helper\s*\(\s*\(([\s\S]{0,1400}?)\)\s*,/gmu)) {
    const names = Array.from(match[1].matchAll(/["']([A-Za-z_][A-Za-z0-9_]*)["']/gu), (nameMatch) => nameMatch[1]);
    const helperNames = names.filter((name) => !name.startsWith("_"));
    if (helperNames.length === 0) {
      continue;
    }
    const defined = helperNames.filter((name) => pythonSourceDefinesName(source, name));
    if (defined.length === 0) {
      missingGroups.push(helperNames);
    }
  }
  if (missingGroups.length === 0) {
    return undefined;
  }

  const visibleGroups = missingGroups
    .slice(0, 3)
    .map((group) => `[${group.slice(0, 6).join(", ")}]`)
    .join("; ");
  return [
    "Generated Python runner has an unresolved helper dispatch mismatch.",
    `_invoke_helper searches helper group(s) with no defined implementation: ${visibleGroups}.`,
    "Define at least one searched helper in each group, or align the helper lookup names with the generated implementation before handoff."
  ].join(" ");
}

async function detectPythonMetricsWriterAdapterMismatch(scriptPath?: string): Promise<string | undefined> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return undefined;
  }
  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return undefined;
  }

  const hasMetricsWriterAdapter =
    source.includes("def _entrypoint_write_metrics") ||
    source.includes("def _write_metrics_payload");
  const hasWriterInvoker =
    source.includes("_entrypoint_invoke(writer,") ||
    source.includes("_call_with_supported_kwargs(writer,") ||
    /\bwriter\s*\(\s*metrics\s*,\s*metrics_path\s*\)/u.test(source) ||
    /\bwriter\s*\(\s*metrics_path\s*,\s*metrics\s*\)/u.test(source);
  if (!hasMetricsWriterAdapter || !hasWriterInvoker) {
    return undefined;
  }

  const writerNames = ["write_metrics_json", "write_metrics", "persist_metrics_json", "save_metrics_json"];
  const writerName = writerNames.find((name) => pythonSourceDefinesName(source, name));
  if (!writerName) {
    return undefined;
  }

  const signature = extractPythonFunctionSignature(source, writerName);
  if (!signature) {
    return undefined;
  }

  const writerParams = extractPythonParameterNames(signature);
  if (writerParams.includes("kwargs")) {
    return undefined;
  }

  const firstParam = writerParams[0] || "unknown";
  const secondParam = writerParams[1] || "unknown";
  const directPositionalWriterAdapter =
    /\bwriter\s*\(\s*metrics\s*,\s*metrics_path\s*\)/u.test(source) ||
    /\bwriter\s*\(\s*metrics_path\s*,\s*metrics\s*\)/u.test(source);
  if (
    directPositionalWriterAdapter &&
    ["config", "runtime_config", "experiment_config"].includes(firstParam) &&
    ["metrics", "payload", "metrics_payload", "aggregated_metrics"].includes(secondParam)
  ) {
    return [
      "Generated Python runner has a metrics writer adapter mismatch.",
      `Entrypoint adapter calls ${writerName}() with metrics/path positional arguments, but ${writerName}() expects '${firstParam}' then '${secondParam}'.`,
      "Pass the generated RuntimeConfig object to the writer or call a path/payload writer whose signature matches the adapter before handoff."
    ].join(" ");
  }

  const requiredParams = writerParams.filter((name) => !name.startsWith("*"));
  const pathParamNames = ["metrics_path", "path", "output_path", "destination"];
  const adapterPathNames = pathParamNames.filter((name) =>
    new RegExp(`\\b${escapeRegex(name)}\\s*=\\s*metrics_path\\b`, "u").test(source)
  );
  const missingRequiredPathParam = requiredParams.find(
    (name) => pathParamNames.includes(name) && !adapterPathNames.includes(name)
  );
  if (missingRequiredPathParam) {
    return [
      "Generated Python runner has a metrics writer adapter mismatch.",
      `Entrypoint adapter does not pass required path argument '${missingRequiredPathParam}' to ${writerName}().`,
      "Pass the writer's actual metrics path parameter name before handoff, or align the writer signature with the adapter."
    ].join(" ");
  }

  const payloadParamNames = ["metrics", "payload", "metrics_payload"];
  if (payloadParamNames.some((name) => writerParams.includes(name))) {
    return undefined;
  }

  const adapterPassesPayloadKeywords = payloadParamNames.some((name) =>
    new RegExp(`\\b${escapeRegex(name)}\\s*=\\s*payload\\b`, "u").test(source)
  );
  if (!adapterPassesPayloadKeywords) {
    return undefined;
  }

  return [
    "Generated Python runner has a metrics writer adapter mismatch.",
    `Entrypoint adapter passes payload as metrics/payload/metrics_payload, but ${writerName}() requires '${firstParam}'.`,
    "Rename the writer payload parameter to one accepted by the adapter, accept **kwargs, or call the writer with its actual required payload parameter before handoff."
  ].join(" ");
}

async function detectPythonAtomicWriteJsonCallOrderMismatch(scriptPath?: string): Promise<string | undefined> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return undefined;
  }
  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return undefined;
  }

  const payloadFirstDefinition = source.match(
    /\ndef\s+atomic_write_json\s*\(\s*(payload|data|obj|metrics|metrics_payload)\b[\s\S]{0,300}?,\s*(path|metrics_path|output_path|destination)\b/u
  );
  if (!payloadFirstDefinition) {
    return undefined;
  }
  const firstParam = payloadFirstDefinition[1] || "payload";
  const secondParam = payloadFirstDefinition[2] || "path";

  const reversedPathCalls = Array.from(
    source.matchAll(/\batomic_write_json\s*\(\s*([^,\n]+(?:\.[A-Za-z_][A-Za-z0-9_]*)?)\s*,/gmu),
    (match) => match[1].trim()
  ).filter((arg) =>
    /(?:^|\.)(?:metrics_path|results_path|output_path|destination|path)$/u.test(arg) ||
    /\bPath\s*\(/u.test(arg)
  );
  if (reversedPathCalls.length === 0) {
    return undefined;
  }

  const visibleCalls = Array.from(new Set(reversedPathCalls)).slice(0, 4).join(", ");
  return [
    "Generated Python runner has an atomic JSON writer call-order mismatch.",
    `atomic_write_json() is defined as ${firstParam}/${secondParam}, but path-like argument(s) are passed first: ${visibleCalls}.`,
    "Call atomic_write_json(payload, path), or redefine the helper with a path-first signature before handoff."
  ].join(" ");
}

async function detectPythonEvaluationSampleDictAccessMismatch(
  scriptPath?: string
): Promise<string | undefined> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return undefined;
  }
  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return undefined;
  }

  if (!/\bclass\s+EvaluationSample\b/u.test(source) || !/\bEvaluationSample\s*\(/u.test(source)) {
    return undefined;
  }
  if (!/\bdef\s+_entrypoint_evaluate_model\s*\(/u.test(source)) {
    return undefined;
  }

  const evaluatorMatch = source.match(
    /\ndef\s+_entrypoint_evaluate_model\s*\([\s\S]*?\n(?=def\s+|class\s+|if\s+__name__\s*==|$)/u
  );
  const evaluatorSource = evaluatorMatch?.[0] || "";
  const objectBackedLoader =
    /\bdef\s+load_evaluation_samples\s*\([\s\S]*?Dict\s*\[[^\]]*List\s*\[\s*EvaluationSample\s*\]/u.test(
      source
    );
  const evaluatorUsesDictAccess =
    /\bfor\s+sample\s+in\s+samples\s*:[\s\S]{0,1600}\bsample\.get\s*\(/u.test(evaluatorSource);
  if (!objectBackedLoader || !evaluatorUsesDictAccess) {
    return undefined;
  }

  return [
    "Generated Python runner has an evaluation sample access mismatch.",
    "Evaluation loaders materialize EvaluationSample objects, but _entrypoint_evaluate_model reads samples with dict-only sample.get(...).",
    "Normalize EvaluationSample objects to mappings before evaluation, or read object attributes such as choices, correct_index, and prompt before handoff."
  ].join(" ");
}

async function detectPythonDictRecipeAttributeAccess(scriptPath?: string): Promise<string | undefined> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return undefined;
  }
  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return undefined;
  }

  const dictBackedRecipeContainers = new Set<string>();
  for (const match of source.matchAll(
    /^\s*([A-Z][A-Z0-9_]*)\s*(?::\s*(?:List|list|Tuple|tuple)\s*\[[^\n=]*Dict[^\n=]*\])?\s*=\s*(?:\[\s*\{|\(\s*\{)/gmu
  )) {
    dictBackedRecipeContainers.add(match[1]);
  }
  if (dictBackedRecipeContainers.size === 0) {
    return undefined;
  }

  const mismatches: string[] = [];
  for (const container of dictBackedRecipeContainers) {
    const accessPattern = new RegExp(`\\brecipe\\.(?:name|recipe_id|display_name)\\b[^\\n]*\\b${escapeRegex(container)}\\b`, "u");
    const match = source.match(accessPattern);
    if (match?.index !== undefined) {
      const line = source.slice(0, match.index).split(/\r?\n/u).length;
      mismatches.push(`${container} at ${path.basename(scriptPath)}:${line}`);
    }
  }
  if (mismatches.length === 0) {
    return undefined;
  }

  return [
    "Generated Python runner treats dict-backed recipe config entries as objects.",
    `Attribute-style recipe access over dict container(s): ${mismatches.slice(0, 6).join(", ")}.`,
    "Use recipe['name'] / recipe.get('name') for dict configs, or keep the recipe container as dataclass/object instances before handoff."
  ].join(" ");
}

async function detectPythonRecipeSpecConstructorKeywordMismatch(scriptPath?: string): Promise<string | undefined> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return undefined;
  }
  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return undefined;
  }

  if (!source.includes("class RecipeSpec:") || !source.includes("RecipeSpec(")) {
    return undefined;
  }

  const classStart = source.indexOf("class RecipeSpec:\n");
  if (classStart < 0) {
    return undefined;
  }
  const bodyStart = classStart + "class RecipeSpec:\n".length;
  const bodyEnd = findPythonClassBodyEnd(source, bodyStart);
  const classBody = source.slice(bodyStart, bodyEnd);
  if (/\n\s+def\s+__init__\s*\(/u.test(`\n${classBody}`)) {
    return undefined;
  }

  const fieldNames = new Set<string>();
  for (const match of classBody.matchAll(/^\s+([A-Za-z_][A-Za-z0-9_]*)\s*:/gmu)) {
    fieldNames.add(match[1]);
  }
  if (fieldNames.size === 0) {
    return undefined;
  }

  const unexpectedKeywords = new Set<string>();
  for (const call of source.matchAll(/\bRecipeSpec\s*\(([\s\S]*?)\)/gu)) {
    const callBody = call[1] || "";
    for (const keyword of callBody.matchAll(/(?:^|[,\n(])\s*([A-Za-z_][A-Za-z0-9_]*)\s*=/gu)) {
      const name = keyword[1];
      if (!fieldNames.has(name)) {
        unexpectedKeywords.add(name);
      }
    }
  }

  if (unexpectedKeywords.size === 0) {
    return undefined;
  }

  const visibleUnexpected = Array.from(unexpectedKeywords).slice(0, 8).join(", ");
  const visibleFields = Array.from(fieldNames).slice(0, 10).join(", ");
  return [
    "Generated Python runner has a RecipeSpec constructor keyword mismatch.",
    `RecipeSpec(...) uses keyword field(s) not accepted by the generated dataclass: ${visibleUnexpected}.`,
    visibleFields ? `Accepted RecipeSpec field(s) include: ${visibleFields}.` : undefined,
    "Keep one consistent RecipeSpec schema, or translate recipe metadata through an explicit factory before handoff."
  ].filter(Boolean).join(" ");
}

function pythonSourceDefinesName(source: string, name: string): boolean {
  const escaped = escapeRegex(name);
  return (
    new RegExp(`\\ndef\\s+${escaped}\\s*\\(`, "u").test(`\n${source}`) ||
    new RegExp(`\\nclass\\s+${escaped}\\b`, "u").test(`\n${source}`) ||
    new RegExp(`\\n${escaped}\\s*=`, "u").test(`\n${source}`)
  );
}

function pythonSourceDefinesOrImportsName(source: string, name: string): boolean {
  const escaped = escapeRegex(name);
  return (
    pythonSourceDefinesName(source, name) ||
    new RegExp(`\\n\\s*from\\s+[\\w.]+\\s+import\\s+[^\\n#]*\\b${escaped}\\b`, "u").test(`\n${source}`) ||
    new RegExp(`\\n\\s*import\\s+${escaped}\\b`, "u").test(`\n${source}`)
  );
}

function ensurePythonDataclassesFieldImport(source: string): string {
  if (!/\bfield\s*\(/u.test(source) || pythonSourceDefinesOrImportsName(source, "field")) {
    return source;
  }
  return insertPythonTopLevelHelperAfterImports(source, "from dataclasses import field\n");
}

async function pythonSourceParsesForRepair(source: string, scriptPath: string): Promise<boolean> {
  const tempPath = `${scriptPath}.autolabos-syntax-check-${process.pid}-${Date.now()}.tmp.py`;
  try {
    await fs.writeFile(tempPath, source, "utf8");
    await execFile(
      "python3",
      [
        "-c",
        "import ast, pathlib, sys\nast.parse(pathlib.Path(sys.argv[1]).read_text(encoding='utf-8'))",
        tempPath
      ],
      { timeout: 10_000 }
    );
    return true;
  } catch {
    return false;
  } finally {
    await fs.unlink(tempPath).catch(() => undefined);
  }
}

function isLikelyInsidePythonTripleQuotedString(source: string, offset: number): boolean {
  let singleQuoteTriples = 0;
  let doubleQuoteTriples = 0;
  for (const match of source.slice(0, offset).matchAll(/'''|"""/gu)) {
    if (match[0] === "'''") {
      singleQuoteTriples += 1;
    } else {
      doubleQuoteTriples += 1;
    }
  }
  return singleQuoteTriples % 2 === 1 || doubleQuoteTriples % 2 === 1;
}

function insertPythonTopLevelHelperAfterImports(source: string, helper: string): string {
  const lines = source.split("\n");
  let offset = 0;
  let lastImportEndOffset = 0;
  let inImportBlock = false;
  let parenDepth = 0;
  let backslashContinued = false;

  const lineEndLength = (index: number) => (index < lines.length - 1 ? 1 : 0);
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index] || "";
    const trimmed = line.trim();
    const lengthWithNewline = line.length + lineEndLength(index);

    if (inImportBlock) {
      parenDepth += (line.match(/\(/gu) || []).length;
      parenDepth -= (line.match(/\)/gu) || []).length;
      backslashContinued = trimmed.endsWith("\\");
      offset += lengthWithNewline;
      lastImportEndOffset = offset;
      if (parenDepth <= 0 && !backslashContinued) {
        inImportBlock = false;
      }
      continue;
    }

    if (trimmed === "" || trimmed.startsWith("#")) {
      offset += lengthWithNewline;
      continue;
    }

    if (/^(?:from\s+\S+\s+import\b|import\s+\S+)/u.test(trimmed)) {
      parenDepth = (line.match(/\(/gu) || []).length - (line.match(/\)/gu) || []).length;
      backslashContinued = trimmed.endsWith("\\");
      offset += lengthWithNewline;
      lastImportEndOffset = offset;
      if (parenDepth > 0 || backslashContinued) {
        inImportBlock = true;
      }
      continue;
    }

    break;
  }

  if (lastImportEndOffset > 0) {
    return `${source.slice(0, lastImportEndOffset)}${helper}${source.slice(lastImportEndOffset)}`;
  }
  return `${helper}${source}`;
}

function replacePythonTopLevelFunctionSource(
  source: string,
  functionName: string,
  replacement: string,
  shouldReplace?: (functionSource: string) => boolean
): string {
  const lines = source.split("\n");
  const offsets: number[] = [];
  let offset = 0;
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index] || "";
    offsets.push(offset);
    offset += line.length + (index < lines.length - 1 ? 1 : 0);
  }

  const escapedName = escapeRegex(functionName);
  const functionStartLine = lines.findIndex((line) =>
    new RegExp(`^def\\s+${escapedName}\\s*\\(`, "u").test(line)
  );
  if (functionStartLine < 0) {
    return source;
  }

  let functionEndLine = lines.length;
  for (let index = functionStartLine + 1; index < lines.length; index += 1) {
    const line = lines[index] || "";
    const trimmed = line.trim();
    if (trimmed.length === 0 || trimmed.startsWith("#")) {
      continue;
    }
    if (!line.startsWith(" ") && !line.startsWith("\t")) {
      functionEndLine = index;
      break;
    }
  }

  const startOffset = offsets[functionStartLine] ?? 0;
  const endOffset = offsets[functionEndLine] ?? source.length;
  const functionSource = source.slice(startOffset, endOffset);
  if (shouldReplace && !shouldReplace(functionSource)) {
    return source;
  }

  const normalizedReplacement = replacement.endsWith("\n") ? replacement : `${replacement}\n`;
  return `${source.slice(0, startOffset)}${normalizedReplacement}${source.slice(endOffset)}`;
}

function extractPythonFunctionSignature(source: string, name: string): string | undefined {
  const escaped = escapeRegex(name);
  const match = new RegExp(`\\ndef\\s+${escaped}\\s*\\(`, "u").exec(`\n${source}`);
  if (!match || match.index < 0) {
    return undefined;
  }
  const normalized = `\n${source}`;
  const openIndex = match.index + match[0].length - 1;
  let depth = 0;
  let signature = "";
  for (let index = openIndex; index < normalized.length; index += 1) {
    const char = normalized[index];
    if (char === "(") {
      depth += 1;
      if (depth === 1) {
        continue;
      }
    } else if (char === ")") {
      depth -= 1;
      if (depth === 0) {
        return signature;
      }
    }
    if (depth >= 1) {
      signature += char;
    }
  }
  return undefined;
}

function extractPythonParameterNames(signature: string): string[] {
  return signature
    .split(",")
    .map((rawParam) => rawParam.replace(/#.*/u, "").trim())
    .filter((param) => param.length > 0 && param !== "/" && param !== "*")
    .map((param) => param.split("=")[0]?.trim() || "")
    .map((param) => param.split(":")[0]?.trim() || "")
    .map((param) => param.replace(/^\*+/u, "").trim())
    .filter((param) => /^[A-Za-z_][A-Za-z0-9_]*$/u.test(param));
}

function extractPythonRequiredParameterNames(signature: string): string[] {
  return splitPythonSignatureParameters(signature)
    .map((rawParam) => rawParam.replace(/#.*/u, "").trim())
    .filter((param) => param.length > 0 && param !== "/" && param !== "*")
    .filter((param) => !param.startsWith("*"))
    .filter((param) => !pythonSignatureParamHasTopLevelDefault(param))
    .map((param) => param.split(":")[0]?.trim() || "")
    .filter((param) => /^[A-Za-z_][A-Za-z0-9_]*$/u.test(param));
}

function splitPythonSignatureParameters(signature: string): string[] {
  const params: string[] = [];
  let current = "";
  let depth = 0;
  let quote: "'" | "\"" | undefined;
  let escaped = false;

  for (const char of signature) {
    if (quote) {
      current += char;
      if (escaped) {
        escaped = false;
      } else if (char === "\\") {
        escaped = true;
      } else if (char === quote) {
        quote = undefined;
      }
      continue;
    }

    if (char === "'" || char === "\"") {
      quote = char;
      current += char;
      continue;
    }
    if (char === "[" || char === "(" || char === "{") {
      depth += 1;
      current += char;
      continue;
    }
    if (char === "]" || char === ")" || char === "}") {
      depth = Math.max(0, depth - 1);
      current += char;
      continue;
    }
    if (char === "," && depth === 0) {
      params.push(current);
      current = "";
      continue;
    }
    current += char;
  }

  if (current.trim().length > 0) {
    params.push(current);
  }

  return params;
}

function pythonSignatureParamHasTopLevelDefault(param: string): boolean {
  let depth = 0;
  let quote: "'" | "\"" | undefined;
  let escaped = false;

  for (const char of param) {
    if (quote) {
      if (escaped) {
        escaped = false;
      } else if (char === "\\") {
        escaped = true;
      } else if (char === quote) {
        quote = undefined;
      }
      continue;
    }
    if (char === "'" || char === "\"") {
      quote = char;
      continue;
    }
    if (char === "[" || char === "(" || char === "{") {
      depth += 1;
      continue;
    }
    if (char === "]" || char === ")" || char === "}") {
      depth = Math.max(0, depth - 1);
      continue;
    }
    if (char === "=" && depth === 0) {
      return true;
    }
  }

  return false;
}

function isImplementStagedLlmTimeoutError(error: unknown): boolean {
  return error instanceof Error && /implement_experiments staged_llm request timed out after \d+ms/.test(error.message);
}

async function clearStagedLlmAttemptArtifacts(runDir: string): Promise<void> {
  const targets = [
    IMPLEMENT_PARTIAL_RESPONSE_ARTIFACT,
    IMPLEMENT_SCAFFOLD_ARTIFACT,
    IMPLEMENT_SCAFFOLD_PROMPT_ARTIFACT,
    IMPLEMENT_SCAFFOLD_RAW_RESPONSE_ARTIFACT,
    IMPLEMENT_DECOMPOSITION_PLAN_ARTIFACT,
    IMPLEMENT_DECOMPOSITION_PLAN_RAW_RESPONSE_ARTIFACT,
    IMPLEMENT_BOOTSTRAP_CONTRACT_ARTIFACT,
    IMPLEMENT_BOOTSTRAP_CONTRACT_PROMPT_ARTIFACT,
    IMPLEMENT_BOOTSTRAP_CONTRACT_RAW_RESPONSE_ARTIFACT,
    IMPLEMENT_FILE_PLAN_ARTIFACT,
    IMPLEMENT_UNIT_PLAN_DIR,
    IMPLEMENT_UNIT_SECTION_DIR,
    IMPLEMENT_UNIT_SKELETON_DIR,
    IMPLEMENT_UNIT_CHUNK_PROMPT_DIR,
    IMPLEMENT_UNIT_CHUNK_RESPONSE_DIR
  ];
  await Promise.all(
    targets.map(async (target) => {
      try {
        await fs.rm(path.join(runDir, target), { force: true, recursive: true });
      } catch {
        // Best effort cleanup only; stale diagnostics should not block a new staged attempt.
      }
    })
  );
}

function isRetryableImplementStagedLlmMaterializationError(error: unknown): boolean {
  return (
    isImplementStagedLlmTimeoutError(error) ||
    isProviderTerminatedStagedLlmError(error) ||
    isMalformedJsonStagedLlmChunkError(error) ||
    isCandidateValidationStagedLlmError(error)
  );
}

export function isMalformedJsonStagedLlmChunkError(error: unknown): boolean {
  return (
    error instanceof Error &&
    (
      error.message === "staged_llm chunk response did not contain a valid JSON object" ||
      /staged_llm chunk response returned chunk_id=.+ but expected/u.test(error.message) ||
      /staged_llm chunk response for .+ contained no content/u.test(error.message)
    )
  );
}

function isCandidateValidationStagedLlmError(error: unknown): boolean {
  return (
    error instanceof Error &&
    /staged_llm chunk response for .+ failed candidate validation:/u.test(error.message)
  );
}

function extractUndefinedUppercaseConstantNames(validationError?: string): string[] {
  if (!validationError || !validationError.includes("uppercase constant")) {
    return [];
  }

  const names: string[] = [];
  for (const match of validationError.matchAll(/\b([A-Z][A-Z0-9_]{2,})\b(?=\s+at\s+)/gu)) {
    if (!names.includes(match[1])) {
      names.push(match[1]);
    }
  }
  return names;
}

function isProviderTerminatedStagedLlmError(error: unknown): boolean {
  if (!(error instanceof Error)) {
    return false;
  }
  const message = error.message.trim().toLowerCase();
  return message === "terminated" || message === "codex oauth backend returned an error: terminated";
}

export function isTransientStagedLlmProviderError(error: unknown): boolean {
  if (!(error instanceof Error)) {
    return false;
  }
  const message = error.message.toLowerCase();
  return (
    /\b(?:502|503|504|520|521|522|523|524)\b/u.test(message) ||
    message.includes("our servers are currently overloaded") ||
    message.includes("please try again later") ||
    message.includes("you can retry your request") ||
    message.includes("an error occurred while processing your request") ||
    message.includes("upstream connect error") ||
    message.includes("disconnect/reset before headers") ||
    message.includes("connection termination") ||
    message.includes("failed before receiving an http response") ||
    message.includes("econnreset") ||
    message.includes("socket hang up")
  );
}

async function delay(ms: number, abortSignal?: AbortSignal): Promise<void> {
  if (ms <= 0) {
    return;
  }
  await new Promise<void>((resolve, reject) => {
    if (abortSignal?.aborted) {
      reject(new Error("aborted"));
      return;
    }
    const timer = setTimeout(() => {
      abortSignal?.removeEventListener("abort", onAbort);
      resolve();
    }, ms);
    const onAbort = () => {
      clearTimeout(timer);
      reject(new Error("aborted"));
    };
    abortSignal?.addEventListener("abort", onAbort, { once: true });
  });
}

function normalizeDynamicDecompositionPlan(
  plan: DynamicDecompositionPlan | undefined,
  workspaceRoot: string
): DynamicDecompositionPlan | undefined {
  if (!plan) {
    return undefined;
  }
  const normalizedUnits = plan.units
    .map((unit) => {
      const normalizedTargetPath = normalizeStoredPath(unit.target_path, workspaceRoot);
      if (unit.generation_mode === "materialize_text_file" && (!normalizedTargetPath || !isMaterializableImplementTextPath(normalizedTargetPath))) {
        return undefined;
      }
      const normalizedUnit: DynamicDecompositionUnit = {
        ...unit,
        target_path: normalizedTargetPath || unit.target_path
      };
      return normalizedUnit;
    })
    .filter((unit): unit is DynamicDecompositionUnit => unit !== undefined);
  if (normalizedUnits.length === 0) {
    return undefined;
  }
  return {
    ...plan,
    units: normalizedUnits
  };
}

function synthesizeDecompositionPlanFromScaffold(
  scaffold: StructuredImplementResponse,
  workspaceRoot: string
): DynamicDecompositionPlan | undefined {
  const targets = collectMaterializableScaffoldTargets(scaffold, workspaceRoot);
  if (targets.length === 0) {
    return undefined;
  }

  return buildDynamicDecompositionPlan({
    objective: "Materialize the runnable implementation artifacts named by the scaffold.",
    strategy: "scaffold_target_local_synthesis",
    rationale:
      "The scaffold already identified concrete text artifacts, so AutoLabOS can avoid an extra provider planning turn and preserve progress under bounded staged implementation.",
    units: targets.map((targetPath, index) => ({
      id: `artifact_${index + 1}`,
      unit_type: inferDecompositionUnitTypeForPath(targetPath),
      title: index === 0 ? "Primary scaffold artifact" : `Scaffold artifact ${index + 1}`,
      purpose:
        index === 0
          ? "Materialize the primary runnable artifact declared by the scaffold."
          : "Materialize an additional text artifact declared by the scaffold.",
      generation_mode: "materialize_text_file",
      target_path: targetPath,
      depends_on: index === 0 ? undefined : ["artifact_1"],
      verification_focus: index === 0 ? ["run_command", "test_command"] : ["artifact_materialized"]
    }))
  });
}

function collectMaterializableScaffoldTargets(scaffold: StructuredImplementResponse, workspaceRoot: string): string[] {
  const candidates = [
    scaffold.script_path,
    ...(scaffold.changed_files || []),
    ...(scaffold.file_plan || [])
  ];
  const targets: string[] = [];
  for (const candidate of candidates) {
    if (typeof candidate !== "string" || candidate.trim().length === 0) {
      continue;
    }
    const normalized = normalizeStoredPath(candidate, workspaceRoot) || candidate.trim();
    if (!isMaterializableImplementTextPath(normalized) || targets.includes(normalized)) {
      continue;
    }
    targets.push(normalized);
  }
  return targets;
}

function inferDecompositionUnitTypeForPath(filePath: string): DynamicDecompositionUnit["unit_type"] {
  const ext = path.extname(filePath).toLowerCase();
  if ([".json", ".yaml", ".yml", ".toml", ".ini", ".cfg"].includes(ext)) {
    return "config_file";
  }
  if (ext === ".md") {
    return "documentation_file";
  }
  return "text_file";
}

function parseDynamicMaterializationPlan(value: unknown): DynamicMaterializationPlan | undefined {
  if (!value || typeof value !== "object") {
    return undefined;
  }
  const record = value as Record<string, unknown>;
  const chunks = Array.isArray(record.chunks)
    ? record.chunks
        .map((item) => parseDynamicMaterializationChunk(item))
        .filter((item): item is DynamicMaterializationChunk => Boolean(item))
    : [];
  if (chunks.length === 0) {
    return undefined;
  }
  return {
    strategy:
      typeof record.strategy === "string" && record.strategy.trim().length > 0
        ? record.strategy.trim()
        : "provider_generated_dynamic_plan",
    rationale:
      typeof record.rationale === "string" && record.rationale.trim().length > 0
        ? record.rationale.trim()
        : "The provider returned a dynamic plan without explicit rationale metadata.",
    chunks
  };
}

function buildLocalMaterializationPlanForUnit(unit: DynamicDecompositionUnit): DynamicMaterializationPlan {
  const targetPath = unit.target_path || "";
  const contentKind = inferMaterializationChunkKindForPath(targetPath, unit.unit_type);
  return {
    strategy: "local_single_chunk_fallback",
    rationale:
      "The provider did not return a materialization subplan within the bounded request, so AutoLabOS uses the approved decomposition unit as one executable materialization chunk.",
    chunks: [
      {
        id: "complete_artifact",
        title: "Complete artifact",
        purpose: unit.purpose || `Materialize ${unit.title}.`,
        content_kind: contentKind,
        include_imports: contentKind === "code_section",
        include_entrypoint: contentKind === "code_section",
        verification_focus: unit.verification_focus
      }
    ]
  };
}

export function buildLocalChunkSubdivisionPlanForChunk(
  chunk: DynamicMaterializationChunk,
  options: { forceSmallerSubdivision?: boolean } = {}
): DynamicMaterializationPlan {
  if (options.forceSmallerSubdivision && isLocalMicroStageChunk(chunk)) {
    return buildLocalTwoPartSubdivisionPlanForChunk(chunk);
  }

  const responsibilityText = (chunk.title + " " + chunk.purpose).toLowerCase();
  const needsExecutionMicroStages =
    /\b(?:preflight|execution|execute|training|evaluation|result|results|evidence|metric|metrics|aggregation|aggregate|reporting|entrypoint)\b/u.test(
      responsibilityText
    );
  const needsContractMicroStages =
    /\b(?:contract|constants?|markers?|seeds?|baseline|conditions?|run[-\s]?plan|model)\b/u.test(responsibilityText);
  if (needsExecutionMicroStages) {
    const stageSpecs: Array<{ suffix: string; title: string; purpose: string; includeImports?: boolean; includeEntrypoint?: boolean }> = [
      {
        suffix: "preflight",
        title: "Preflight and ordered run-plan setup",
        purpose: "Resolve runtime context, environment checks, model/data/task availability, and the ordered run-plan contract before executing any condition.",
        includeImports: chunk.include_imports
      },
      {
        suffix: "one_run",
        title: "Single condition execution helper",
        purpose: "Implement one bounded condition/seed execution path with explicit structured failure capture."
      },
      {
        suffix: "raw_records",
        title: "Raw evidence and row persistence",
        purpose: "Persist per-run raw records, stdout/stderr excerpts, and failure evidence before aggregate reporting."
      },
      {
        suffix: "aggregation",
        title: "Aggregate metric computation",
        purpose: "Compute baseline-relative metrics, per-task summaries, dispersion fields, and completion counts from raw rows."
      },
      {
        suffix: "wiring",
        title: "Parent chunk wiring and final contract handoff",
        purpose: "Wire the parent chunk helpers together and expose any entrypoint or downstream call sites required by the original parent chunk.",
        includeEntrypoint: chunk.include_entrypoint
      }
    ];
    const chunks = stageSpecs.map((stage, index): DynamicMaterializationChunk => ({
      ...chunk,
      id: chunk.id + "_" + stage.suffix,
      title: chunk.title + ": " + stage.title,
      purpose: chunk.purpose + " " + stage.purpose,
      include_imports: index === 0 ? stage.includeImports === true : false,
      include_entrypoint: stage.includeEntrypoint === true,
      depends_on: index === 0 ? chunk.depends_on : [chunk.id + "_" + stageSpecs[index - 1].suffix]
    }));
    return {
      strategy: "local_execution_micro_stage_subdivision_fallback",
      rationale:
        "The provider did not return a forced-smaller subdivision subplan within the bounded request, so AutoLabOS splits the execution/result parent chunk into dependency-safe micro-stages.",
      chunks
    };
  }

  if (needsContractMicroStages) {
    const stageSpecs: Array<{ suffix: string; title: string; purpose: string; includeImports?: boolean; includeEntrypoint?: boolean }> = [
      {
        suffix: "identity",
        title: "Model and runtime identity constants",
        purpose: "Define only model/runtime identity, budget, and static file-path constants needed by the parent contract.",
        includeImports: chunk.include_imports
      },
      {
        suffix: "conditions",
        title: "Condition marker schema",
        purpose: "Define condition marker fields, condition objects, and marker normalization without execution or aggregation logic."
      },
      {
        suffix: "seeds",
        title: "Seed schedule and baseline contract",
        purpose: "Define seed schedules, baseline/comparator ordering, and planned run identifiers without training/evaluation code."
      },
      {
        suffix: "validation",
        title: "Run-plan contract validation",
        purpose: "Add small validation helpers that check the run-plan contract and expose structured errors before downstream execution.",
        includeEntrypoint: chunk.include_entrypoint
      }
    ];
    const chunks = stageSpecs.map((stage, index): DynamicMaterializationChunk => ({
      ...chunk,
      id: chunk.id + "_" + stage.suffix,
      title: chunk.title + ": " + stage.title,
      purpose: chunk.purpose + " " + stage.purpose,
      include_imports: index === 0 ? stage.includeImports === true : false,
      include_entrypoint: stage.includeEntrypoint === true,
      depends_on: index === 0 ? chunk.depends_on : [chunk.id + "_" + stageSpecs[index - 1].suffix]
    }));
    return {
      strategy: "local_contract_micro_stage_subdivision_fallback",
      rationale:
        "The provider did not return a forced-smaller subdivision subplan within the bounded request, so AutoLabOS splits the contract/constants parent chunk into dependency-safe micro-stages.",
      chunks
    };
  }

  if (!options.forceSmallerSubdivision) {
    return {
      strategy: "local_single_chunk_subdivision_fallback",
      rationale:
        "The provider did not return a chunk subdivision subplan within the bounded request, so AutoLabOS uses the approved parent chunk directly.",
      chunks: [chunk]
    };
  }

  return buildLocalTwoPartSubdivisionPlanForChunk(chunk);
}

function isLocalMicroStageChunk(chunk: DynamicMaterializationChunk): boolean {
  return /_(?:preflight|one_run|raw_records|aggregation|wiring|identity|conditions|seeds|validation)$/u.test(chunk.id);
}

function buildLocalTwoPartSubdivisionPlanForChunk(chunk: DynamicMaterializationChunk): DynamicMaterializationPlan {
  const firstChunk: DynamicMaterializationChunk = {
    ...chunk,
    id: chunk.id + "_part_1",
    title: chunk.title + " part 1",
    purpose: chunk.purpose + " Cover the first bounded portion of this parent chunk.",
    include_entrypoint: false
  };
  const secondChunk: DynamicMaterializationChunk = {
    ...chunk,
    id: chunk.id + "_part_2",
    title: chunk.title + " part 2",
    purpose: chunk.purpose + " Cover the second bounded portion of this parent chunk and finish the parent contract.",
    include_imports: false,
    include_entrypoint: chunk.include_entrypoint,
    depends_on: [firstChunk.id]
  };
  return {
    strategy: "local_two_part_subdivision_fallback",
    rationale:
      "The provider did not return a forced-smaller subdivision subplan within the bounded request, so AutoLabOS splits the parent chunk into two ordered local parts.",
    chunks: [firstChunk, secondChunk]
  };
}

function inferMaterializationChunkKindForPath(
  filePath: string,
  unitType?: DynamicDecompositionUnit["unit_type"]
): DynamicMaterializationChunk["content_kind"] {
  const ext = path.extname(filePath).toLowerCase();
  if ([".json", ".yaml", ".yml", ".toml", ".ini", ".cfg"].includes(ext) || unitType === "config_file") {
    return "config_block";
  }
  if (ext === ".md" || unitType === "documentation_file") {
    return "documentation_section";
  }
  if ([".py", ".ts", ".tsx", ".js", ".jsx", ".mjs", ".cjs", ".sh"].includes(ext)) {
    return "code_section";
  }
  return "text_section";
}

export function buildLocalPythonUtilityChunkContent(
  filePath: string,
  chunk: Pick<DynamicMaterializationChunk, "title" | "purpose" | "content_kind">
): string | undefined {
  if (!isPythonMaterializationPath(filePath) || chunk.content_kind !== "code_section") {
    return undefined;
  }
  const responsibilityText = `${chunk.title} ${chunk.purpose}`.toLowerCase();
  const isJsonPathSerializationHelper =
    /\bjson\b/u.test(responsibilityText) &&
    /\b(?:path|paths|directory|directories|serialization|serializable|artifact|atomic|write|writer|persistence)\b/u.test(
      responsibilityText
    ) &&
    /\b(?:helper|helpers|utility|utilities|serialization|persistence|writer|writers)\b/u.test(responsibilityText);
  if (!isJsonPathSerializationHelper) {
    return undefined;
  }

  return [
    "def utc_now_iso():",
    "    return datetime.now(timezone.utc).isoformat().replace(\"+00:00\", \"Z\")",
    "",
    "",
    "def ensure_dir(path_value):",
    "    Path(path_value).mkdir(parents=True, exist_ok=True)",
    "    return Path(path_value)",
    "",
    "",
    "def ensure_parent_dir(path_value):",
    "    path_obj = Path(path_value)",
    "    path_obj.parent.mkdir(parents=True, exist_ok=True)",
    "    return path_obj",
    "",
    "",
    "def to_jsonable(value):",
    "    if hasattr(value, \"to_dict\") and callable(value.to_dict):",
    "        return to_jsonable(value.to_dict())",
    "    if hasattr(value, \"__dataclass_fields__\"):",
    "        return to_jsonable(asdict(value))",
    "    if isinstance(value, Path):",
    "        return str(value)",
    "    if isinstance(value, Mapping):",
    "        return {str(key): to_jsonable(item) for key, item in value.items()}",
    "    if isinstance(value, (list, tuple, set)):",
    "        return [to_jsonable(item) for item in value]",
    "    if isinstance(value, float) and not math.isfinite(value):",
    "        return None",
    "    return value",
    "",
    "",
    "def atomic_write_json(path_value, payload):",
    "    path_obj = ensure_parent_dir(path_value)",
    "    tmp_path = path_obj.with_suffix(path_obj.suffix + \".tmp\")",
    "    with tmp_path.open(\"w\", encoding=\"utf-8\") as handle:",
    "        json.dump(to_jsonable(payload), handle, indent=2, sort_keys=True)",
    "        handle.write(\"\\n\")",
    "    os.replace(tmp_path, path_obj)",
    "    return path_obj",
    "",
    "",
    "def write_json_atomic(path_value, payload):",
    "    return atomic_write_json(path_value, payload)",
    "",
    "",
    "def write_json_file(path_value, payload):",
    "    return atomic_write_json(path_value, payload)",
    "",
    "",
    "def read_json_file(path_value, default=None):",
    "    path_obj = Path(path_value)",
    "    if not path_obj.exists():",
    "        return default",
    "    with path_obj.open(\"r\", encoding=\"utf-8\") as handle:",
    "        return json.load(handle)",
    "",
    "",
    "def append_jsonl(path_value, payload):",
    "    path_obj = ensure_parent_dir(path_value)",
    "    with path_obj.open(\"a\", encoding=\"utf-8\") as handle:",
    "        handle.write(json.dumps(to_jsonable(payload), sort_keys=True))",
    "        handle.write(\"\\n\")",
    "    return path_obj",
    "",
    "",
    "def safe_float(value, default=None):",
    "    try:",
    "        result = float(value)",
    "    except Exception:",
    "        return default",
    "    return result if math.isfinite(result) else default",
    "",
    "",
    "def safe_int(value, default=None):",
    "    try:",
    "        return int(value)",
    "    except Exception:",
    "        return default"
  ].join("\n");
}

function parseDynamicMaterializationChunk(value: unknown): DynamicMaterializationChunk | undefined {
  if (!value || typeof value !== "object") {
    return undefined;
  }
  const record = value as Record<string, unknown>;
  const id = typeof record.id === "string" && record.id.trim().length > 0 ? record.id.trim() : undefined;
  const title = typeof record.title === "string" && record.title.trim().length > 0 ? record.title.trim() : undefined;
  const purpose =
    typeof record.purpose === "string" && record.purpose.trim().length > 0 ? record.purpose.trim() : undefined;
  const contentKind = normalizeMaterializationChunkKind(record.content_kind);
  if (!id || !title || !purpose || !contentKind) {
    return undefined;
  }
  return {
    id,
    title,
    purpose,
    content_kind: contentKind,
    include_imports: record.include_imports === true,
    include_entrypoint: record.include_entrypoint === true,
    depends_on: Array.isArray(record.depends_on)
      ? record.depends_on.filter((item): item is string => typeof item === "string" && item.trim().length > 0)
      : undefined,
    verification_focus: Array.isArray(record.verification_focus)
      ? record.verification_focus.filter((item): item is string => typeof item === "string" && item.trim().length > 0)
      : undefined
  };
}

function normalizeMaterializationChunkKind(
  value: unknown
): DynamicMaterializationChunk["content_kind"] | undefined {
  return value === "code_section" ||
    value === "config_block" ||
    value === "documentation_section" ||
    value === "text_section"
    ? value
    : undefined;
}

function parseImplementBootstrapContract(value: unknown): ImplementBootstrapContract | undefined {
  if (!value || typeof value !== "object") {
    return undefined;
  }
  const record = value as Record<string, unknown>;
  const requirements = Array.isArray(record.requirements)
    ? record.requirements
        .map((item) => parseImplementBootstrapRequirement(item))
        .filter((item): item is ImplementBootstrapRequirement => Boolean(item))
    : [];
  const checks = Array.isArray(record.checks)
    ? record.checks
        .map((item) => parseImplementBootstrapCheck(item))
        .filter((item): item is ImplementBootstrapCheck => Boolean(item))
    : [];
  if (requirements.length === 0 && checks.length === 0 && typeof record.summary !== "string") {
    return undefined;
  }
  return {
    version: asNumber(record.version) || 1,
    strategy: asOptionalString(record.strategy),
    summary: asOptionalString(record.summary),
    requires_network: record.requires_network === true,
    requires_warm_cache: record.requires_warm_cache === true,
    blocking_reason: asOptionalString(record.blocking_reason),
    remediation: asOptionalStringArray(record.remediation),
    requirements,
    checks
  };
}

export function parseImplementBootstrapContractFromText(text: string): ImplementBootstrapContract | undefined {
  const direct = parseImplementBootstrapContract(parseJsonObject(text));
  if (direct) {
    return direct;
  }

  for (const candidate of parseJsonObjectsFromText(text)) {
    const contract = parseImplementBootstrapContract(candidate);
    if (contract) {
      return contract;
    }
  }
  return undefined;
}

function shouldRequireExplicitBootstrapPlanning(
  taskSpec: ImplementTaskSpec,
  scaffold: StructuredImplementResponse
): boolean {
  const signals = [
    taskSpec.goal,
    taskSpec.context.topic,
    taskSpec.context.plan_excerpt,
    taskSpec.context.hypotheses_excerpt,
    taskSpec.context.previous_summary || "",
    taskSpec.context.runner_feedback?.summary || "",
    scaffold.summary || "",
    scaffold.run_command || ""
  ]
    .join("\n")
    .toLowerCase();
  return (
    taskSpec.context.comparison_contract?.comparison_mode === "baseline_first_locked" ||
    /(peft|adapter|instruction tuning|condition grid|condition sweep|huggingface|transformer|tokenizer|language model|autotokenizer|automodelforcausallm)/u.test(
      signals
    )
  );
}

function buildDefaultImplementBootstrapContract(taskSpec: ImplementTaskSpec): ImplementBootstrapContract {
  return {
    version: 1,
    strategy: "deterministic_default",
    summary: "No explicit bootstrap risks were identified before code generation.",
    requires_network: false,
    requires_warm_cache: false,
    requirements: [],
    checks: []
  };
}

function parseImplementBootstrapRequirement(value: unknown): ImplementBootstrapRequirement | undefined {
  if (!value || typeof value !== "object") {
    return undefined;
  }
  const record = value as Record<string, unknown>;
  const id = asOptionalString(record.id);
  const kind = normalizeBootstrapRequirementKind(record.kind);
  const source = normalizeBootstrapRequirementSource(record.source);
  const requiredFor = asOptionalStringArray(record.required_for);
  if (!id || !kind || !source || !requiredFor || requiredFor.length === 0) {
    return undefined;
  }
  return {
    id,
    kind,
    source,
    required_for: requiredFor,
    local_path: asOptionalString(record.local_path),
    availability: normalizeBootstrapAvailability(record.availability),
    summary: asOptionalString(record.summary),
    remediation: asOptionalString(record.remediation)
  };
}

function parseImplementBootstrapCheck(value: unknown): ImplementBootstrapCheck | undefined {
  if (!value || typeof value !== "object") {
    return undefined;
  }
  const record = value as Record<string, unknown>;
  const id = asOptionalString(record.id);
  const checkType = normalizeBootstrapCheckType(record.check_type);
  const target = asOptionalString(record.target);
  const reason = asOptionalString(record.reason);
  if (!id || !checkType || !target || !reason) {
    return undefined;
  }
  return {
    id,
    check_type: checkType,
    target,
    reason
  };
}

function normalizeBootstrapRequirementKind(value: unknown): ImplementBootstrapRequirement["kind"] | undefined {
  const normalized = asOptionalString(value);
  return normalized === "model" ||
    normalized === "tokenizer" ||
    normalized === "dataset" ||
    normalized === "binary" ||
    normalized === "library" ||
    normalized === "reference_data" ||
    normalized === "service"
    ? normalized
    : undefined;
}

function normalizeBootstrapRequirementSource(value: unknown): ImplementBootstrapRequirement["source"] | undefined {
  const normalized = asOptionalString(value);
  return normalized === "huggingface" ||
    normalized === "local" ||
    normalized === "python" ||
    normalized === "system" ||
    normalized === "other"
    ? normalized
    : undefined;
}

function normalizeBootstrapAvailability(
  value: unknown
): ImplementBootstrapRequirement["availability"] | undefined {
  const normalized = asOptionalString(value);
  return normalized === "assumed_local" ||
    normalized === "download_required" ||
    normalized === "unknown"
    ? normalized
    : undefined;
}

function normalizeBootstrapCheckType(value: unknown): ImplementBootstrapCheck["check_type"] | undefined {
  const normalized = asOptionalString(value);
  return normalized === "path_exists" ||
    normalized === "command_available" ||
    normalized === "python_module_available"
    ? normalized
    : undefined;
}

function asOptionalString(value: unknown): string | undefined {
  return typeof value === "string" && value.trim().length > 0 ? value.trim() : undefined;
}

function asOptionalStringArray(value: unknown): string[] | undefined {
  if (!Array.isArray(value)) {
    return undefined;
  }
  const normalized = value.filter((item): item is string => typeof item === "string" && item.trim().length > 0);
  return normalized.length > 0 ? normalized : undefined;
}

export async function evaluateImplementBootstrapContract(params: {
  contract: ImplementBootstrapContract;
  workspaceRoot: string;
}): Promise<{ status: "pass" | "warn" | "block"; summary: string; missing: string[] }> {
  const missing: string[] = [];
  const passedPythonModuleChecks: string[] = [];
  const missingPythonModuleChecks: string[] = [];
  for (const requirement of params.contract.requirements) {
    const localPath = normalizeStoredPath(requirement.local_path, params.workspaceRoot);
    if (localPath && !(await fileExists(localPath))) {
      if (requirement.source === "huggingface") {
        continue;
      }
      if (isLikelyGeneratedExperimentOutputPath(localPath, params.workspaceRoot)) {
        continue;
      }
      missing.push(`${requirement.id}: expected local path is missing (${formatArtifactPath(localPath, params.workspaceRoot)})`);
    }
  }

  for (const check of params.contract.checks) {
    if (check.check_type === "path_exists") {
      const targetPath = normalizeStoredPath(check.target, params.workspaceRoot);
      if (!targetPath || !(await fileExists(targetPath))) {
        if (targetPath && isLikelyGeneratedExperimentOutputPath(targetPath, params.workspaceRoot)) {
          continue;
        }
        missing.push(`${check.id}: required path is missing (${check.target})`);
      }
    } else if (check.check_type === "command_available") {
      if (!(await isBootstrapCommandAvailable(check.target, params.workspaceRoot))) {
        missing.push(`${check.id}: required command is unavailable (${check.target})`);
      }
    } else if (check.check_type === "python_module_available") {
      if (await isBootstrapPythonModuleAvailable(check.target, params.workspaceRoot)) {
        passedPythonModuleChecks.push(check.target);
      } else if (isOptionalBootstrapPythonModuleCheck(check, params.contract)) {
        continue;
      } else {
        missingPythonModuleChecks.push(check.target);
        missing.push(`${check.id}: required Python module is unavailable (${check.target})`);
      }
    }
  }

  const blockingReason = normalizeActionableBootstrapBlockingReason(params.contract.blocking_reason);
  const actionableBlockingReason =
    blockingReason &&
    isPythonPackageMissingBootstrapReason(blockingReason) &&
    passedPythonModuleChecks.length > 0 &&
    missingPythonModuleChecks.length === 0
      ? undefined
      : blockingReason;
  if (actionableBlockingReason || missing.length > 0) {
    return {
      status: "block",
      summary:
        actionableBlockingReason ||
        `Bootstrap contract failed under the current execution policy: ${missing.join("; ")}`,
      missing
    };
  }
  if (params.contract.requires_network) {
    return {
      status: "warn",
      summary:
        params.contract.summary ||
        "Bootstrap contract indicates remote assets and will proceed as a network-assisted run if fetched on demand.",
      missing
    };
  }
  return {
    status: "pass",
    summary: params.contract.summary || "Bootstrap contract is compatible with the current execution policy.",
    missing
  };
}

async function isBootstrapCommandAvailable(command: string, cwd: string): Promise<boolean> {
  const normalized = command.trim();
  if (!/^[A-Za-z0-9_.+/-]+$/u.test(normalized)) {
    return false;
  }
  try {
    await execFile("which", [normalized], { cwd, timeout: 5_000 });
    return true;
  } catch {
    return false;
  }
}

async function isBootstrapPythonModuleAvailable(moduleName: string, cwd: string): Promise<boolean> {
  const normalized = moduleName.trim();
  if (!/^[A-Za-z_]\w*(?:\.[A-Za-z_]\w*)*$/u.test(normalized)) {
    return false;
  }
  try {
    await execFile(
      "python",
      [
        "-c",
        [
          "import importlib",
          `importlib.import_module(${JSON.stringify(normalized)})`
        ].join("; ")
      ],
      { cwd, timeout: 10_000 }
    );
    return true;
  } catch {
    return false;
  }
}

function isPythonPackageMissingBootstrapReason(reason: string): boolean {
  const lower = reason.toLowerCase();
  return (
    lower.includes("missing required python package") ||
    lower.includes("missing required python packages") ||
    lower.includes("missing python package") ||
    lower.includes("missing python packages")
  );
}

function isOptionalBootstrapPythonModuleCheck(
  check: ImplementBootstrapCheck,
  contract: ImplementBootstrapContract
): boolean {
  const target = check.target.trim().toLowerCase();
  const relatedRequirements = contract.requirements.filter((requirement) => {
    if (requirement.kind !== "library" || requirement.source !== "python") {
      return false;
    }
    const haystack = [
      requirement.id,
      requirement.summary || "",
      requirement.remediation || "",
      ...requirement.required_for
    ]
      .join(" ")
      .toLowerCase();
    return haystack.includes(target);
  });
  const text = [
    check.reason,
    ...relatedRequirements.flatMap((requirement) => [
      requirement.summary || "",
      requirement.remediation || "",
      ...requirement.required_for
    ])
  ]
    .join(" ")
    .toLowerCase();
  if (
    ["sklearn", "scikit_learn", "scikit-learn"].includes(target) &&
    /\b(?:accuracy|metric|metrics|scoring|score|evaluation_metrics)\b/u.test(text)
  ) {
    return true;
  }

  return (
    /\b(optional|if used|when used|only if used|useful for|nice-to-have|non-blocking)\b/u.test(text) ||
    /\b(?:if|when)\s+(?:the\s+)?(?:selected|fallback|chosen|configured|active|runtime)\b/u.test(text)
  );
}

function isLikelyGeneratedExperimentOutputPath(filePath: string, workspaceRoot: string): boolean {
  if (!isPathInsideOrEqual(filePath, workspaceRoot)) {
    return false;
  }
  const relativePath = path.relative(workspaceRoot, filePath).replace(/\\/g, "/");
  if (!relativePath.startsWith("outputs/") || !relativePath.includes("/experiment/")) {
    return false;
  }
  const basename = path.basename(filePath).toLowerCase();
  return (
    basename.endsWith(".py") ||
    /(?:^|_)(?:baseline|bootstrap|condition|conditions|experiment|manifest|metrics|portfolio|result|results|run|study|summary|verify)(?:_|\.|$)/u.test(
      basename
    )
  );
}

function normalizeActionableBootstrapBlockingReason(reason: string | undefined): string | undefined {
  if (!reason) {
    return undefined;
  }
  const normalized = reason.trim();
  const lower = normalized.toLowerCase();
  if (
    lower.includes("no known non-network blocker") ||
    lower.includes("no known non network blocker") ||
    lower.includes("no concrete non-network blocker") ||
    lower.includes("no concrete non network blocker")
  ) {
    return undefined;
  }
  const uncertaintySignals = [
    "none known except",
    "if network access is unavailable",
    "if ",
    "if torch",
    "if the",
    "unless",
    "may fail",
    "might fail",
    "could fail",
    "availability is unknown",
    "unknown"
  ];
  const concreteBlockSignals = [
    "is missing",
    "not found",
    "does not exist",
    "unavailable",
    "cannot execute",
    "permission denied",
    "requires manual",
    "blocked by policy"
  ];
  const describesUncertainty = uncertaintySignals.some((signal) => lower.includes(signal));
  const describesConcreteBlock = concreteBlockSignals.some((signal) => lower.includes(signal));
  if (describesUncertainty && !describesConcreteBlock) {
    return undefined;
  }
  return normalized;
}

function shouldUseSectionedSkeletonForTarget(filePath: string): boolean {
  return isPythonMaterializationPath(filePath);
}

function isPythonMaterializationPath(filePath: string): boolean {
  return path.extname(filePath).toLowerCase() === ".py";
}

function buildCanonicalSectionedSkeleton(params: {
  filePath: string;
  unit: DynamicDecompositionUnit;
  materializationPlan: DynamicMaterializationPlan;
  sections: PlannedMaterializationSection[];
}): string {
  const commentPrefix = isPythonMaterializationPath(params.filePath) ? "# " : "";
  const header = [
    `${commentPrefix}AUTOLABOS CANONICAL SKELETON`,
    `${commentPrefix}Target: ${params.filePath}`,
    `${commentPrefix}Unit: ${params.unit.title}`,
    `${commentPrefix}Strategy: ${params.materializationPlan.strategy || "dynamic_materialization"}`,
    ""
  ];
  const sectionBlocks = params.sections.flatMap((entry, index) => [
    `${commentPrefix}BEGIN AUTOLABOS SECTION ${entry.section.id} :: ${entry.section.title}`,
    `${commentPrefix}Purpose: ${entry.section.purpose}`,
    `${commentPrefix}Order: ${index + 1}/${params.sections.length}`,
    `${commentPrefix}END AUTOLABOS SECTION ${entry.section.id}`,
    ""
  ]);
  return [...header, ...sectionBlocks].join("\n").trimEnd() + "\n";
}

function applySectionContentToCanonicalSkeleton(
  skeleton: string,
  sectionId: string,
  sectionContent: string,
  filePath: string
): string {
  const commentPrefix = isPythonMaterializationPath(filePath) ? "# " : "";
  const startMarkerPattern = new RegExp(
    `${escapeRegex(`${commentPrefix}BEGIN AUTOLABOS SECTION ${sectionId}`)}[^\\n]*\\n${escapeRegex(commentPrefix)}Purpose:[^\\n]*\\n${escapeRegex(commentPrefix)}Order:[^\\n]*\\n`,
    "u"
  );
  const endMarker = `${commentPrefix}END AUTOLABOS SECTION ${sectionId}`;
  const startMatch = skeleton.match(startMarkerPattern);
  if (!startMatch || startMatch.index == null) {
    throw new Error(`canonical skeleton is missing section marker for ${sectionId}`);
  }
  const contentStart = startMatch.index + startMatch[0].length;
  const endIndex = skeleton.indexOf(endMarker, contentStart);
  if (endIndex < 0) {
    throw new Error(`canonical skeleton is missing end marker for ${sectionId}`);
  }
  return `${skeleton.slice(0, contentStart)}${sectionContent.trimEnd()}\n${skeleton.slice(endIndex)}`;
}

function stripCanonicalSkeletonMarkers(content: string, filePath: string): string {
  const commentPrefix = isPythonMaterializationPath(filePath) ? "# " : "";
  const stripped = content
    .split("\n")
    .filter((line) => {
      const normalizedLine = line.trimStart();
      return !normalizedLine.startsWith(`${commentPrefix}AUTOLABOS CANONICAL SKELETON`) &&
        !normalizedLine.startsWith(`${commentPrefix}Target:`) &&
        !normalizedLine.startsWith(`${commentPrefix}Unit:`) &&
        !normalizedLine.startsWith(`${commentPrefix}Strategy:`) &&
        !normalizedLine.startsWith(`${commentPrefix}BEGIN AUTOLABOS SECTION`) &&
        !normalizedLine.startsWith(`${commentPrefix}Purpose:`) &&
        !normalizedLine.startsWith(`${commentPrefix}Order:`) &&
        !normalizedLine.startsWith(`${commentPrefix}END AUTOLABOS SECTION`);
    })
    .join("\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
  return stripped.length > 0 ? `${stripped}\n` : "";
}

function escapeRegex(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function isMaterializableTextUnit(unit: DynamicDecompositionUnit): boolean {
  return unit.generation_mode === "materialize_text_file" && typeof unit.target_path === "string" && unit.target_path.length > 0;
}

function compactDraftForChunkPrompt(draft: string): { has_content: boolean; excerpt?: string } {
  const trimmed = draft.trim();
  if (!trimmed) {
    return { has_content: false };
  }
  return {
    has_content: true,
    excerpt: trimBlock(trimmed, 4000)
  };
}

function appendDraftSection(draft: string, section: string): string {
  return draft.trim().length > 0 ? `${draft.trimEnd()}\n\n${section.trimStart()}` : section;
}

function sanitizeArtifactId(value: string): string {
  return value.replace(/[^a-zA-Z0-9._-]+/g, "_");
}

function parseStructuredFileEditResponse(
  text: string,
  workspaceRoot: string,
  expectedPath: string
): StructuredImplementFileEdit {
  const parsed = parseJsonObject(text);
  if (!parsed || typeof parsed !== "object") {
    throw new Error(`staged_llm file generation for ${expectedPath} did not return a JSON object`);
  }
  const record = parsed as Record<string, unknown>;
  const normalizedPath = normalizeStoredPath(asString(record.path) || expectedPath, workspaceRoot);
  const content = asString(record.content);
  if (!normalizedPath || content === undefined) {
    throw new Error(`staged_llm file generation for ${expectedPath} omitted path/content`);
  }
  return {
    path: normalizedPath,
    content
  };
}

async function materializeStructuredFileEdits(fileEdits: StructuredImplementFileEdit[]): Promise<void> {
  for (const item of fileEdits) {
    await ensureDir(path.dirname(item.path));
    await fs.writeFile(item.path, item.content, "utf8");
  }
}

function parseJsonObject(text: string): unknown {
  const trimmed = text.trim();
  if (!trimmed) {
    return undefined;
  }
  try {
    return JSON.parse(trimmed);
  } catch {
    // continue
  }

  const fenceMatch = trimmed.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenceMatch) {
    try {
      return JSON.parse(fenceMatch[1]);
    } catch {
      // continue
    }
  }

  const first = trimmed.indexOf("{");
  const last = trimmed.lastIndexOf("}");
  if (first >= 0 && last > first) {
    try {
      return JSON.parse(trimmed.slice(first, last + 1));
    } catch {
      return undefined;
    }
  }
  return undefined;
}

function parseJsonObjectsFromText(text: string): unknown[] {
  const candidates: unknown[] = [];
  for (const candidateText of extractBalancedJsonObjectStrings(text)) {
    try {
      candidates.push(JSON.parse(candidateText));
    } catch {
      // Ignore non-JSON brace spans and keep scanning for a schema-valid object.
    }
  }
  return candidates;
}

function extractBalancedJsonObjectStrings(text: string): string[] {
  const results: string[] = [];
  const seen = new Set<string>();
  for (let start = text.indexOf("{"); start >= 0; start = text.indexOf("{", start + 1)) {
    const candidate = extractBalancedJsonObjectStringFrom(text, start);
    if (candidate && !seen.has(candidate)) {
      seen.add(candidate);
      results.push(candidate);
    }
  }
  return results;
}

function extractBalancedJsonObjectStringFrom(text: string, start: number): string | undefined {
  let depth = 0;
  let inString = false;
  let escaped = false;

  for (let index = start; index < text.length; index += 1) {
    const char = text[index];
    if (inString) {
      if (escaped) {
        escaped = false;
      } else if (char === "\\") {
        escaped = true;
      } else if (char === "\"") {
        inString = false;
      }
      continue;
    }

    if (char === "\"") {
      inString = true;
      continue;
    }
    if (char === "{") {
      depth += 1;
      continue;
    }
    if (char === "}" && depth > 0) {
      depth -= 1;
      if (depth === 0) {
        return text.slice(start, index + 1);
      }
    }
  }
  return undefined;
}

function normalizeStoredPath(filePath: string | undefined, workspaceRoot: string): string | undefined {
  if (!filePath) {
    return undefined;
  }
  const candidate = mapAliasedWorkspacePathToPrimary(filePath, workspaceRoot);
  const resolved = path.isAbsolute(candidate) ? candidate : path.resolve(workspaceRoot, candidate);
  if (!isPathInsideOrEqual(resolved, workspaceRoot)) {
    return undefined;
  }
  return resolved;
}

function trimBlock(text: string, limit: number): string {
  const trimmed = text.trim();
  if (!trimmed) {
    return "";
  }
  if (trimmed.length <= limit) {
    return trimmed;
  }
  return `${trimmed.slice(0, limit)}\n...<truncated>`;
}

function derivePlannedConditionContract(input: {
  plan?: string;
  brief?: string;
  objectiveMetric: string;
}): PlannedConditionContract | undefined {
  const planContractText = extractSelectedDesignContractText(input.plan) || input.plan;
  const fullContractText = [input.plan, input.brief, input.objectiveMetric].filter(Boolean).join("\n");
  const planText = [planContractText, input.objectiveMetric].filter(Boolean).join("\n");
  const planHasSpecificContract = Boolean(
    input.plan?.trim() &&
      (extractRankDropoutConditionMarkers(planText).length > 0 ||
        parseRepeatedSeedRunContract(planText) ||
        extractSeedSchedule(planText).length > 1 ||
        parsePlannedConditionContractCount(planText))
  );
  const text = planHasSpecificContract
    ? planText
    : [input.plan, input.brief, input.objectiveMetric].filter(Boolean).join("\n");
  if (!text.trim()) {
    return undefined;
  }
  const markers = new Set<string>();
  for (const segment of extractPlannedConditionSegments(text)) {
    const marker = canonicalPlannedConditionMarker(segment);
    if (marker) {
      markers.add(marker);
    }
  }
  const rankDropoutMarkers = extractRankDropoutConditionMarkers(text);
  for (const marker of rankDropoutMarkers) {
    markers.add(marker);
  }
  const fallbackRankDropoutMarkers = planHasSpecificContract
    ? extractRankDropoutConditionMarkers(fullContractText)
    : [];
  addMarkerIf(text, markers, "unmodified_base", /\bunmodified\s+base\b|\bno[-\s]?tune\b|\buntuned\b/iu);
  addMarkerIf(text, markers, "standard_tuned_baseline", /\bvanilla\s+adapter\b|\bstandard\s+adapter\b|\bnamed\s+tuned\s+baseline[^\n.]*\badapter\b/iu);
  addMarkerIf(text, markers, "rank_stabilized_adapter", /\brs[-\s]?adapter\b/iu);
  addMarkerIf(text, markers, "decomposed_adapter", /\bdecomposed_adapter\b/iu);
  addMarkerIf(text, markers, "ia3", /\bia3\b/iu);
  addMarkerIf(text, markers, "prefix_tuning", /\bprefix[-\s]?tuning\b/iu);
  addMarkerIf(text, markers, "prompt_tuning", /\bprompt[-\s]?tuning\b/iu);

  const repeatedRunContract = parseRepeatedSeedRunContract(text);
  const seedSchedule = extractSeedSchedule(text);
  const evaluationContract = parseFullEvaluationContract(text);
  const baselineConditionMarker =
    extractBaselineRankDropoutMarker(text) ||
    (planHasSpecificContract ? extractBaselineRankDropoutMarker(fullContractText) : undefined);
  const requiredCountFromText =
    repeatedRunContract?.cellCount ||
    parsePlannedConditionContractCount(text);
  const exactRankDropoutMarkers =
    rankDropoutMarkers.length >= 2 && (!requiredCountFromText || rankDropoutMarkers.length === requiredCountFromText)
      ? rankDropoutMarkers
      : fallbackRankDropoutMarkers.length >= 2 &&
          (!requiredCountFromText || fallbackRankDropoutMarkers.length === requiredCountFromText)
        ? fallbackRankDropoutMarkers
        : rankDropoutMarkers.length > 0
          ? rankDropoutMarkers
          : undefined;
  const requiredCount =
    requiredCountFromText ||
    (exactRankDropoutMarkers && exactRankDropoutMarkers.length >= 2 ? exactRankDropoutMarkers.length : undefined);
  const inferredRepeatedRunCount =
    repeatedRunContract?.runCount ||
    (requiredCount && seedSchedule.length > 1 ? requiredCount * seedSchedule.length : undefined);
  const inferredMinimumSeedsPerCondition =
    repeatedRunContract?.seedsPerCell || (seedSchedule.length > 1 ? seedSchedule.length : undefined);
  const primaryMetricKey = extractPrimaryMetricKey(input.objectiveMetric) || extractPrimaryMetricKey(text);
  if (markers.size === 0 && requiredCount === undefined && !primaryMetricKey) {
    return undefined;
  }
  let markerList = exactRankDropoutMarkers || [...markers].slice(0, 8);
  if (baselineConditionMarker && markerList.includes(baselineConditionMarker)) {
    markerList = [
      baselineConditionMarker,
      ...markerList.filter((marker) => marker !== baselineConditionMarker)
    ];
  }
  const notes = [
    "Derived from the governed plan/brief text; implement_experiments must preserve these planned condition semantics.",
    "If a marker cannot run because the installed stack lacks support, record that condition as failed with evidence rather than substituting a different recipe."
  ];
  if (repeatedRunContract || seedSchedule.length > 0) {
    notes.push(
      "This is a repeated-seed evidence-scale contract. Do not compress repeated cells or seed schedules into a single pilot condition or a single condition-parameter grid marker.",
      "The runner must emit per-seed/per-condition rows plus aggregate variance or confidence-interval fields when the plan asks for repeated-run evidence."
    );
  }
  return {
    required_condition_count: requiredCount,
    required_run_count: inferredRepeatedRunCount,
    seed_schedule: seedSchedule.length > 0 ? seedSchedule : undefined,
    minimum_seeds_per_condition: inferredMinimumSeedsPerCondition,
    baseline_condition_marker: baselineConditionMarker,
    tuned_only: markerList.some((marker) => marker !== "unmodified_base"),
    required_condition_markers: markerList,
    primary_metric_key: primaryMetricKey,
    full_evaluation_required: evaluationContract.fullEvaluationRequired || undefined,
    minimum_eval_examples_per_task:
      Object.keys(evaluationContract.minimumEvalExamplesPerTask).length > 0
        ? evaluationContract.minimumEvalExamplesPerTask
        : undefined,
    notes
  };
}

function extractSelectedDesignContractText(plan?: string): string | undefined {
  if (!plan?.trim()) {
    return undefined;
  }
  const selectedMatch = /(?:^|\n)selected_design:\s*(?:\n|$)/iu.exec(plan);
  if (!selectedMatch || selectedMatch.index === undefined) {
    return undefined;
  }
  const start = selectedMatch.index + (selectedMatch[0].startsWith("\n") ? 1 : 0);
  const rest = plan.slice(start);
  const stopMatch = /\n(?:shortlisted_designs|execution|dropped_hypotheses|hypothesis_filter):\s*(?:\n|$)/iu.exec(rest);
  const selectedBlock = stopMatch?.index !== undefined ? rest.slice(0, stopMatch.index) : rest;
  return selectedBlock.trim() || undefined;
}

function extractPlannedConditionSegments(text: string): string[] {
  const segments: string[] = [];
  for (const match of text.matchAll(/\bconditions?\s*:\s*([^\n]+)/giu)) {
    segments.push(
      ...(match[1] || "")
        .split(";")
        .map((item) => item.trim())
        .filter(Boolean)
    );
  }
  return segments;
}

function canonicalPlannedConditionMarker(segment: string): string | undefined {
  if (/\bunmodified\s+base\b|\bno[-\s]?tune\b|\buntuned\b/iu.test(segment)) {
    return "unmodified_base";
  }
  if (/\brs[-\s]?adapter\b/iu.test(segment)) {
    return "rank_stabilized_adapter";
  }
  if (/\bdecomposed_adapter\b/iu.test(segment)) {
    return "decomposed_adapter";
  }
  if (/\bvanilla\s+adapter\b|\bstandard\s+adapter\b/iu.test(segment)) {
    return "standard_tuned_baseline";
  }
  if (/\bia3\b/iu.test(segment)) {
    return "ia3";
  }
  if (/\bprefix[-\s]?tuning\b/iu.test(segment)) {
    return "prefix_tuning";
  }
  if (/\bprompt[-\s]?tuning\b/iu.test(segment)) {
    return "prompt_tuning";
  }
  const slug = segment
    .replace(/^[Cc]\d+\s*/u, "")
    .toLowerCase()
    .replace(/[^a-z0-9]+/gu, "_")
    .replace(/^_+|_+$/gu, "")
    .slice(0, 48);
  return slug || undefined;
}

function addMarkerIf(text: string, markers: Set<string>, marker: string, pattern: RegExp): void {
  if (pattern.test(text)) {
    markers.add(marker);
  }
}

function parsePlannedConditionContractCount(text: string): number | undefined {
  const numericMatch =
    text.match(/\b(\d+)\s+conditions?\s+x\b/iu) ||
    text.match(/\b(?:exactly\s+)?(\d+)\s+(?:planned\s+)?(?:experimental\s+)?conditions?\b/iu) ||
    text.match(/\bno\s+more\s+than\s+(\d+)\s+experimental\s+conditions?\b/iu);
  if (numericMatch) {
    const parsed = Number.parseInt(numericMatch[1] || "", 10);
    if (Number.isFinite(parsed) && parsed > 0) {
      return parsed;
    }
  }
  if (/\bfour[-\s]?condition\b|\bbaseline\s+plus\s+three\s+alternatives\b|\bone\s+tuned\s+baseline\s+and\s+three\s+alternative\b/iu.test(text)) {
    return 4;
  }
  const conditionSegments = extractPlannedConditionSegments(text);
  return conditionSegments.length >= 2 ? conditionSegments.length : undefined;
}

function parseRepeatedSeedRunContract(
  text: string
): { cellCount?: number; seedsPerCell?: number; runCount?: number } | undefined {
  const explicitRuns =
    text.match(/\bexecute\s+(\d+)\s+(?:train[-\s]?plus[-\s]?eval|train[-\s]?and[-\s]?eval|training[-\s]?and[-\s]?evaluation)?\s*runs?\s+total\b/iu) ||
    text.match(/\b(\d+)\s+runs?\s+total\b/iu) ||
    text.match(/\btotal\s+planned\s+(?:train\/eval|train[-\s]?eval|train[-\s]?and[-\s]?eval|training[-\s]?and[-\s]?evaluation)\s+jobs?\s*[:=]\s*(\d+)\b/iu) ||
    text.match(/\b(?:train\/eval|train[-\s]?eval|train[-\s]?and[-\s]?eval|training[-\s]?and[-\s]?evaluation)\s+(?:jobs?|runs?)\s+total\s*[:=]?\s*(\d+)\b/iu);
  const conditionsPerSeedMatch =
    text.match(/\btotal\s+training\s+conditions?\s+per\s+seed\s*[:=]\s*(\d+)\b/iu) ||
    text.match(/\bconditions?\s+per\s+seed\s*[:=]\s*(\d+)\b/iu);
  const cellSeedMatch =
    text.match(/\b(\d+)\s+repeated\s+cells?\s*[x×]\s*(\d+)[-\s]*seeds?\b/iu) ||
    text.match(/\b(\d+)\s+ranks?\s*[x×]\s*(\d+)[-\s]*seeds?\b/iu) ||
    text.match(/\b(\d+)[-\s]*cells?\s*[x×]\s*(\d+)[-\s]*seeds?\b/iu);
  const cellCount = cellSeedMatch
    ? Number.parseInt(cellSeedMatch[1] || "", 10)
    : conditionsPerSeedMatch
      ? Number.parseInt(conditionsPerSeedMatch[1] || "", 10)
      : undefined;
  const seedsPerCell = cellSeedMatch ? Number.parseInt(cellSeedMatch[2] || "", 10) : undefined;
  const runCount = explicitRuns
    ? Number.parseInt(explicitRuns[1] || "", 10)
    : cellCount && seedsPerCell
      ? cellCount * seedsPerCell
      : undefined;
  const normalizedCellCount = Number.isFinite(cellCount) && (cellCount || 0) > 0 ? cellCount : undefined;
  const normalizedSeedsPerCell = Number.isFinite(seedsPerCell) && (seedsPerCell || 0) > 0 ? seedsPerCell : undefined;
  const normalizedRunCount = Number.isFinite(runCount) && (runCount || 0) > 0 ? runCount : undefined;
  if (!normalizedCellCount && !normalizedSeedsPerCell && !normalizedRunCount) {
    return undefined;
  }
  return {
    cellCount: normalizedCellCount,
    seedsPerCell: normalizedSeedsPerCell,
    runCount: normalizedRunCount
  };
}

function extractSeedSchedule(text: string): number[] {
  const seeds = new Set<number>();
  for (const match of text.matchAll(/\bseeds?\s*(?:=|:)?\s*\[([0-9,\s]+)\]/giu)) {
    const raw = match[1] || "";
    for (const token of raw.split(",")) {
      const parsed = Number.parseInt(token.trim(), 10);
      if (Number.isFinite(parsed)) {
        seeds.add(parsed);
      }
    }
  }
  for (const match of text.matchAll(/\bseeds?\s*(?:=|:)?\s*\{([0-9,\s]+)\}/giu)) {
    const raw = match[1] || "";
    for (const token of raw.split(",")) {
      const parsed = Number.parseInt(token.trim(), 10);
      if (Number.isFinite(parsed)) {
        seeds.add(parsed);
      }
    }
  }
  for (const match of text.matchAll(
    /\bseeds?\s*(?:=|:)?\s+(\d+(?:\s*,\s*(?:and\s+)?\d+)+(?:\s*,?\s*and\s+\d+)?|\d+\s+and\s+\d+)/giu
  )) {
    const raw = match[1] || "";
    const parsedSeeds = [...raw.matchAll(/\b\d+\b/gu)]
      .map((seedMatch) => Number.parseInt(seedMatch[0], 10))
      .filter((parsed) => Number.isFinite(parsed));
    if (parsedSeeds.length < 2) {
      continue;
    }
    for (const seed of parsedSeeds) {
      seeds.add(seed);
    }
  }
  return [...seeds].sort((left, right) => left - right);
}

function parseFullEvaluationContract(text: string): {
  fullEvaluationRequired: boolean;
  minimumEvalExamplesPerTask: Record<string, number>;
} {
  const lower = text.toLowerCase();
  const fullEvaluationRequired =
    /\bfull\b[\s\S]{0,120}\b(?:benchmark|task|validation|evaluation)\b/iu.test(text) ||
    /\b(?:benchmark|task)\b[\s\S]{0,120}\bfull\b[\s\S]{0,120}\b(?:validation|evaluation|split|set)s?\b/iu.test(text);
  const minimumEvalExamplesPerTask: Record<string, number> = {};
  const taskCount = extractTaskEvaluationCount(text, ["benchmark", "task", "evaluation"]);
  if (taskCount !== undefined) {
    minimumEvalExamplesPerTask.benchmark_task = taskCount;
  }
  if (
    /\bfull\b/u.test(lower) &&
    (Object.keys(minimumEvalExamplesPerTask).length > 0 ||
      /\b(?:benchmark|task)\b[\s\S]{0,160}\bvalidation\s+(?:sets?|splits?)\b/iu.test(text))
  ) {
    return { fullEvaluationRequired: true, minimumEvalExamplesPerTask };
  }
  return { fullEvaluationRequired, minimumEvalExamplesPerTask };
}

function extractTaskEvaluationCount(text: string, taskAliases: string[]): number | undefined {
  const aliasPattern = taskAliases.map((alias) => alias.replace(/[-_]/gu, "[-_\\s]?")).join("|");
  const patterns = [
    new RegExp(`\\b(?:${aliasPattern})\\b[\\s\\S]{0,120}?\\bn\\s*=\\s*(\\d+)\\b`, "iu"),
    new RegExp(`\\b(?:${aliasPattern})\\b[\\s\\S]{0,120}?\\b(\\d+)\\s+(?:validation|evaluation)\\s+examples?\\b`, "iu"),
    new RegExp(`\\b(\\d+)\\s+(?:validation|evaluation)\\s+examples?\\b[\\s\\S]{0,120}?\\b(?:${aliasPattern})\\b`, "iu")
  ];
  for (const pattern of patterns) {
    const match = text.match(pattern);
    const parsed = match ? Number.parseInt(match[1] || "", 10) : NaN;
    if (Number.isFinite(parsed) && parsed > 0) {
      return parsed;
    }
  }
  return undefined;
}

function extractRankDropoutConditionMarkers(text: string): string[] {
  const markers = new Set<string>();
  const repeatedCellsText = extractRepeatedCellsText(text);
  const explicitSearchText = repeatedCellsText || text;
  if (!repeatedCellsText) {
    for (const marker of extractRankDropoutGridMarkers(text)) {
      markers.add(marker);
    }
  }
  for (const match of explicitSearchText.matchAll(
    /\brank[\s_=-]*(\d+)[\s,;/:-]*(?:adapter[_\s-]*)?(?:dropout|drop)[\s_=-]*([0-9]+(?:[._][0-9]+)?)/giu
  )) {
    const rank = Number.parseInt(match[1] || "", 10);
    const dropout = parseDropoutNumber(match[2] || "");
    if (Number.isFinite(rank) && dropout !== undefined) {
      markers.add(rankDropoutMarker(rank, dropout));
    }
  }

  for (const match of text.matchAll(
    /\brank\s+(\d+)\s+and\s+rank\s+(\d+)\s+with\s+dropout\s+([0-9]+(?:\.[0-9]+)?)\s+(?:versus|vs\.?)\s+([0-9]+(?:\.[0-9]+)?)/giu
  )) {
    const ranks = [Number.parseInt(match[1] || "", 10), Number.parseInt(match[2] || "", 10)];
    const dropouts = [parseDropoutNumber(match[3] || ""), parseDropoutNumber(match[4] || "")].filter(
      (value): value is number => value !== undefined
    );
    for (const rank of ranks) {
      if (!Number.isFinite(rank)) {
        continue;
      }
      for (const dropout of dropouts) {
        markers.add(rankDropoutMarker(rank, dropout));
      }
    }
  }

  return [...markers].sort(rankDropoutMarkerSort);
}

function extractRankDropoutGridMarkers(text: string): string[] {
  const markers = new Set<string>();
  for (const match of text.matchAll(
    /\branks?(?:\s+in)?\s+`?\{([^}]+)\}`?\s*(?:[x×]|and)\s*(?:adapter\s+)?dropouts?(?:\s+in)?\s+`?\{([^}]+)\}`?/giu
  )) {
    const ranks = parseNumericList(match[1] || "").map((value) => Math.trunc(value));
    const dropouts = parseNumericList(match[2] || "");
    for (const rank of ranks) {
      if (!Number.isFinite(rank) || rank <= 0) {
        continue;
      }
      for (const dropout of dropouts) {
        markers.add(rankDropoutMarker(rank, dropout));
      }
    }
  }
  for (const match of text.matchAll(
    /\branks?(?:\s+in)?\s+`?\{([^}]+)\}`?[^\n.]{0,80}?\b(?:fixed\s+)?(?:adapter\s+)?dropout\s*(?:=|at|fixed\s+at|of)?\s*`?([0-9]+(?:[._][0-9]+)?)`?/giu
  )) {
    const ranks = parseNumericList(match[1] || "").map((value) => Math.trunc(value));
    const dropout = parseDropoutNumber(match[2] || "");
    if (dropout === undefined) {
      continue;
    }
    for (const rank of ranks) {
      if (!Number.isFinite(rank) || rank <= 0) {
        continue;
      }
      markers.add(rankDropoutMarker(rank, dropout));
    }
  }
  return [...markers].sort(rankDropoutMarkerSort);
}

function parseNumericList(value: string): number[] {
  return value
    .split(/[,;]|\band\b/giu)
    .map((token) => Number.parseFloat(token.trim().replace(/_/gu, ".")))
    .filter((parsed) => Number.isFinite(parsed));
}

function extractRepeatedCellsText(text: string): string | undefined {
  const match = text.match(/\brepeated\s+cells?\s+(?:are|:)\s+([^\n.]+)/iu);
  return match?.[1];
}

function extractBaselineRankDropoutMarker(text: string): string | undefined {
  const match =
    text.match(
      /\bbaseline\s+condition\s*:\s*rank\s*[=:_-]?\s*(\d+)[^\n;]*?\b(?:dropout|drop)\s*[=:_-]?\s*([0-9]+(?:[._][0-9]+)?)/iu
    ) ||
    text.match(
      /\bbaseline\s+(?:condition|cell|marker)?\s*(?:is|=|:)?\s*rank\s*[=:_-]?\s*(\d+)[^\n,;]*?\b(?:dropout|drop)\s*[=:_-]?\s*([0-9]+(?:[._][0-9]+)?)/iu
    );
  if (!match) {
    return undefined;
  }
  const rank = Number.parseInt(match[1] || "", 10);
  const dropout = parseDropoutNumber(match[2] || "");
  if (!Number.isFinite(rank) || dropout === undefined) {
    return undefined;
  }
  return rankDropoutMarker(rank, dropout);
}

function parseDropoutNumber(value: string): number | undefined {
  const parsed = Number.parseFloat(value.replace(/_/gu, "."));
  return Number.isFinite(parsed) ? parsed : undefined;
}

function rankDropoutMarker(rank: number, dropout: number): string {
  return `condition_${rank}_parameter_${formatDropoutMarkerToken(dropout)}`;
}

function formatDropoutMarkerToken(value: number): string {
  const trimmed = value.toFixed(4).replace(/0+$/u, "");
  return (trimmed.endsWith(".") ? `${trimmed}0` : trimmed).replace(/\./gu, "_");
}

function rankDropoutMarkerSort(left: string, right: string): number {
  const leftParsed = parseRankDropoutMarkerForSort(left);
  const rightParsed = parseRankDropoutMarkerForSort(right);
  if (leftParsed.rank !== rightParsed.rank) {
    return leftParsed.rank - rightParsed.rank;
  }
  return leftParsed.dropout - rightParsed.dropout;
}

function parseRankDropoutMarkerForSort(marker: string): { rank: number; dropout: number } {
  const match = marker.match(/^condition_(\d+)_parameter_([0-9_]+)$/u);
  return {
    rank: match ? Number.parseInt(match[1] || "0", 10) : 0,
    dropout: match ? parseDropoutNumber(match[2] || "0") || 0 : 0
  };
}

function extractPrimaryMetricKey(text: string): string | undefined {
  const match = text.match(/\b[a-z][a-z0-9_]*(?:delta_vs_baseline|improvement_over_baseline)\b/iu);
  return match?.[0];
}

function compactTaskSpecForStagedLlmPrompt(taskSpec: ImplementTaskSpec): Record<string, unknown> {
  return {
    goal: trimBlock(taskSpec.goal, 160),
    acceptance_criteria: taskSpec.acceptance_criteria.slice(0, 2).map((item) => trimBlock(item, 120)),
    non_goals: taskSpec.non_goals.slice(0, 2).map((item) => trimBlock(item, 100)),
    constraints: taskSpec.constraints.slice(0, 3).map((item) => trimBlock(item, 120)),
    workspace: {
      public_dir: taskSpec.workspace.public_dir,
      metrics_path: taskSpec.workspace.metrics_path
    },
    execution: taskSpec.execution,
    context: {
      topic: trimBlock(taskSpec.context.topic, 160),
      objective_metric: trimBlock(taskSpec.context.objective_metric, 140),
      plan_excerpt: trimBlock(taskSpec.context.plan_excerpt, 600),
      hypotheses_excerpt: trimBlock(taskSpec.context.hypotheses_excerpt, 200),
      previous_summary: trimBlock(taskSpec.context.previous_summary || "", 120) || undefined,
      previous_run_command: trimBlock(taskSpec.context.previous_run_command || "", 120) || undefined,
      previous_script: taskSpec.context.previous_script,
      implementation_contract_feedback: taskSpec.context.implementation_contract_feedback
        ? {
            summary: trimBlock(taskSpec.context.implementation_contract_feedback.summary, 360),
            stderr_excerpt: trimBlock(taskSpec.context.implementation_contract_feedback.stderr_excerpt || "", 360) || undefined,
            blocking_findings: taskSpec.context.implementation_contract_feedback.blocking_findings.slice(0, 6),
            suggested_next_action: trimBlock(
              taskSpec.context.implementation_contract_feedback.suggested_next_action,
              240
            )
          }
        : undefined,
      comparison_contract: taskSpec.context.comparison_contract
        ? {
            plan_id: taskSpec.context.comparison_contract.plan_id,
            comparison_mode: taskSpec.context.comparison_contract.comparison_mode,
            baseline_first_required: taskSpec.context.comparison_contract.baseline_first_required,
            baseline_candidate_ids: taskSpec.context.comparison_contract.baseline_candidate_ids.slice(0, 2),
            budget_profile: taskSpec.context.comparison_contract.budget_profile,
            evaluator_contract_id: taskSpec.context.comparison_contract.evaluator_contract_id
          }
        : undefined,
      planned_condition_contract: taskSpec.context.planned_condition_contract,
      plan_changed: taskSpec.context.plan_changed,
      plan_hash: taskSpec.context.plan_hash
    }
  };
}

function compactTaskSpecForBootstrapPrompt(taskSpec: ImplementTaskSpec): Record<string, unknown> {
  return {
    goal: trimBlock(taskSpec.goal, 120),
    workspace: {
      public_dir: taskSpec.workspace.public_dir,
      metrics_path: taskSpec.workspace.metrics_path
    },
    execution: {
      runner: taskSpec.execution.runner,
      timeout_sec: taskSpec.execution.timeout_sec
    },
    context: {
      topic: trimBlock(taskSpec.context.topic, 120),
      objective_metric: trimBlock(taskSpec.context.objective_metric, 100),
      previous_script: taskSpec.context.previous_script,
      implementation_contract_feedback: taskSpec.context.implementation_contract_feedback
        ? {
            summary: trimBlock(taskSpec.context.implementation_contract_feedback.summary, 240),
            blocking_findings: taskSpec.context.implementation_contract_feedback.blocking_findings.slice(0, 4)
          }
        : undefined,
      comparison_contract: taskSpec.context.comparison_contract
        ? {
            comparison_mode: taskSpec.context.comparison_contract.comparison_mode,
            baseline_first_required: taskSpec.context.comparison_contract.baseline_first_required,
            budget_profile: taskSpec.context.comparison_contract.budget_profile
          }
        : undefined,
      planned_condition_contract: taskSpec.context.planned_condition_contract
    }
  };
}

