  const resolverPattern =
    /aggregate_fn\s*=\s*_main_resolve_callable\(\(\n\s*"aggregate_experiment_metrics",\n\s*"aggregate_candidate_metrics",\n\s*"rank_and_aggregate_results",\n\s*"build_ranked_metrics",\n\s*\)\)/u;
