    "        keyword.get(\"dataset_cache_dir\")",
    "        or keyword.get(\"data_cache_dir\")",
    "        or keyword.get(\"cache_dir\")",
    "        or _autolabos_value_from_config_or_args(config, args, \"dataset_cache_dir\")",
