    "                config=config,",
    "                seed=_autolabos_seed,",
    "                cache_dir=getattr(_autolabos_eval_args, \"dataset_cache_dir\", None),",
    "            )",
    "    raise RuntimeError(\"No generated benchmark loader was available for benchmark evaluator alias.\")",
