  const callAttemptsPattern =
    /(\n(\s*)for name in candidate_names:\n\s+func = globals\(\)\.get\(name\)\n\s+if not callable\(func\):\n\s+continue\n)(\s*)call_attempts\s*=\s*\(/u;
