    "    )",
    "    metrics_path = _autolabos_value(\"metrics_path\") or globals().get(\"DEFAULT_METRICS_PATH\")",
    "    train_examples = (",
    "        _autolabos_value(\"train_examples\")",
    "        or _autolabos_value(\"instruction_examples\")",
    "        or _autolabos_value(\"instruction_dataset\")",
    "    )",
