async function detectPythonRunCommandArgparseMismatch(
  scriptPath?: string,
  runCommand?: string
): Promise<string | undefined> {
  if (!scriptPath || path.extname(scriptPath) !== ".py" || !runCommand?.trim()) {
    return undefined;
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return undefined;
  }

  if (!/\bargparse\b/u.test(source) || !/\badd_argument\s*\(/u.test(source)) {
    return undefined;
  }
  if (/\bparse_known_args\s*\(/u.test(source)) {
    return undefined;
  }

  const acceptedFlags = extractPythonArgparseLongFlags(source);
  if (acceptedFlags.size === 0) {
    return undefined;
  }

  const commandFlags = extractLongOptionFlags(runCommand);
  const unsupported = commandFlags.filter((flag) => !acceptedFlags.has(flag));
  if (unsupported.length === 0) {
    const noValueFlags = extractPythonArgparseNoValueLongFlags(source);
    const valuedNoValueFlags = extractLongOptionFlagsWithValues(runCommand).filter((flag) => noValueFlags.has(flag));
    if (valuedNoValueFlags.length === 0) {
      return undefined;
    }

    return `run_command passes value(s) to Python argparse flag(s) that do not accept values: ${valuedNoValueFlags.join(
      ", "
    )}. Align run_command with the generated runner CLI or change those flags to accept explicit values before handoff.`;
  }

  const acceptedPreview = [...acceptedFlags].sort().slice(0, 20).join(", ");
  return `run_command passes unsupported Python argparse flag(s): ${unsupported.join(
    ", "
  )}. Accepted flags include: ${acceptedPreview}. Align run_command with the generated runner CLI or add explicit argparse aliases before handoff.`;
}

export async function repairPythonOutputDirArgparseAlias(
  scriptPath?: string,
  runCommand?: string
): Promise<{ repaired: boolean; message?: string }> {
  if (!scriptPath || path.extname(scriptPath) !== ".py" || !runCommand?.trim()) {
    return { repaired: false };
  }

  if (!extractLongOptionFlags(runCommand).includes("--output-dir")) {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (!/\bargparse\b/u.test(source) || !/\badd_argument\s*\(/u.test(source)) {
    return { repaired: false };
  }
  const acceptedFlags = extractPythonArgparseLongFlags(source);
  let lines = source.split(/\r?\n/u);
  let nextSource = source;
  let addedAlias = false;
  const dedupedLines: string[] = [];
  let sawSingleLineOutputDirAliasInParser = false;
  let removedDuplicateAlias = false;
  for (const line of lines) {
    if (/^\s*def\s+\w+\s*\(/u.test(line) || /\bparser\s*=\s*argparse\.ArgumentParser\s*\(/u.test(line)) {
      sawSingleLineOutputDirAliasInParser = false;
    }
    if (/^\s*parser\.add_argument\(\s*["']--output-dir["']/u.test(line)) {
      if (sawSingleLineOutputDirAliasInParser) {
        removedDuplicateAlias = true;
        continue;
      }
      sawSingleLineOutputDirAliasInParser = true;
    }
    dedupedLines.push(line);
  }
  if (removedDuplicateAlias) {
    nextSource = dedupedLines.join("\n");
    lines = dedupedLines;
  }
  for (let index = 0; index < lines.length; index += 1) {
    if (!/\badd_argument\s*\(/u.test(lines[index])) {
      continue;
    }
    const call = extractPythonCallExpression(lines, index);
    if (!call || !/["']--public-dir["']/u.test(call.text) || /["']--output-dir["']/u.test(call.text)) {
      continue;
    }
    let sameParserAlreadyAcceptsOutputDir = false;
    for (let previousIndex = index - 1; previousIndex >= 0; previousIndex -= 1) {
      const previousLine = lines[previousIndex] || "";
      if (/^\s*def\s+\w+\s*\(/u.test(previousLine) || /\bparser\s*=\s*argparse\.ArgumentParser\s*\(/u.test(previousLine)) {
        break;
      }
      if (/^\s*parser\.add_argument\(\s*["']--output-dir["']/u.test(previousLine)) {
        sameParserAlreadyAcceptsOutputDir = true;
        break;
      }
    }
    if (sameParserAlreadyAcceptsOutputDir) {
      continue;
    }
    const callLineCount = call.text.split(/\r?\n/u).length;
    const followingParserLines = lines.slice(index + callLineCount, index + callLineCount + 4).join("\n");
    if (/parser\.add_argument\(\s*["']--output-dir["']/u.test(followingParserLines)) {
      continue;
    }
    const indentMatch = call.text.match(/^(\s*)/u);
    const indent = indentMatch?.[1] || "";
    const destMatch = call.text.match(/\bdest\s*=\s*["']([A-Za-z_]\w*)["']/u);
    const dest = destMatch?.[1] || "public_dir";
    const typeMatch = call.text.match(/\btype\s*=\s*([A-Za-z_][\w.]*)/u);
    const typeArg = typeMatch ? `, type=${typeMatch[1]}` : "";
    const aliasLine = `${indent}parser.add_argument('--output-dir', dest='${dest}'${typeArg}, default=None, help='Alias for --public-dir used by AutoLabOS run_experiments.')`;
    nextSource = nextSource.replace(call.text, `${call.text}\n${aliasLine}`);
    addedAlias = true;
  }

  if (addedAlias || removedDuplicateAlias) {
    await fs.writeFile(scriptPath, nextSource, "utf8");
    return {
      repaired: true,
      message: `Added --output-dir argparse alias to ${path.basename(scriptPath)} before handoff.`
    };
  }

  if (acceptedFlags.has("--output-dir")) {
    return { repaired: false };
  }

  const returnParserPattern = /^(\s*)return\s+parser\s*$/mu;
  if (!returnParserPattern.test(source)) {
    return { repaired: false };
  }

  nextSource = source.replace(
    returnParserPattern,
    (_match, indent: string) => [
      `${indent}parser.add_argument('--output-dir', default='.', help='Public output directory for AutoLabOS run artifacts.')`,
      `${indent}return parser`
    ].join("\n")
  );
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Added --output-dir argparse alias to ${path.basename(scriptPath)} before handoff.`
  };
}

async function repairPythonPrivateRunDirArgparseAlias(
  scriptPath?: string
): Promise<{ repaired: boolean; message?: string }> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (
    !/\bargparse\b/u.test(source) ||
    !/\badd_argument\s*\(/u.test(source) ||
    !/\bargs\.private_run_dir\b/u.test(source)
  ) {
    return { repaired: false };
  }
  const acceptedFlags = extractPythonArgparseLongFlags(source);
  if (acceptedFlags.has("--private-run-dir")) {
    return { repaired: false };
  }

  const returnParserPattern = /^(\s*)return\s+parser\s*$/mu;
  if (!returnParserPattern.test(source)) {
    return { repaired: false };
  }

  const defaultExpr = /\bPRIVATE_RUN_DIR\b/u.test(source) ? "PRIVATE_RUN_DIR" : "'.'";
  const nextSource = source.replace(
    returnParserPattern,
    (_match, indent: string) => [
      `${indent}parser.add_argument('--private-run-dir', dest='private_run_dir', default=${defaultExpr}, help='Private AutoLabOS run directory for non-public artifacts.')`,
      `${indent}return parser`
    ].join("\n")
  );
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Added --private-run-dir argparse alias to ${path.basename(scriptPath)} before handoff.`
  };
}

async function repairPythonModelNameArgparseDestAlias(
  scriptPath?: string
): Promise<{ repaired: boolean; message?: string }> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (
    !/\bargparse\b/u.test(source) ||
    !/\badd_argument\s*\(/u.test(source) ||
    !/["']--model-name-or-path["']/u.test(source)
  ) {
    return { repaired: false };
  }

  const readsModelName =
    /\bargs\.model_name\b/u.test(source) || /_arg_value\s*\(\s*args\s*,\s*["']model_name["']/u.test(source);
  if (!readsModelName) {
    return { repaired: false };
  }

  const lines = source.split(/\r?\n/u);
  let nextSource = source;
  for (let index = 0; index < lines.length; index += 1) {
    if (!/\badd_argument\s*\(/u.test(lines[index])) {
      continue;
    }
    const call = extractPythonCallExpression(lines, index);
    if (!call || !/["']--model-name-or-path["']/u.test(call.text) || /\bdest\s*=/u.test(call.text)) {
      continue;
    }

    const repairedCall = call.text.replace(
      /(["']--model-name-or-path["']\s*,?)/u,
      "$1\n        dest=\"model_name\","
    );
    if (repairedCall !== call.text) {
      nextSource = nextSource.replace(call.text, repairedCall);
    }
    break;
  }

  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Aligned --model-name-or-path argparse destination with args.model_name in ${path.basename(scriptPath)} before handoff.`
  };
}

function escapeRegExpLiteral(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/gu, "\\$&");
}

async function repairPythonRunCommandArgparseAliases(
  scriptPath?: string,
  runCommand?: string
): Promise<{ repaired: boolean; message?: string }> {
  if (!scriptPath || path.extname(scriptPath) !== ".py" || !runCommand?.trim()) {
    return { repaired: false };
  }

  const commandFlags = new Set(extractLongOptionFlags(runCommand));
  const aliasPairs = [
    {
      commandFlag: "--budget-timeout-sec",
      parserFlag: "--timeout-sec"
    },
    {
      commandFlag: "--metrics-out",
      parserFlag: "--metrics-path"
    },
    {
      commandFlag: "--plan",
      parserFlag: "--plan-path"
    },
    {
      commandFlag: "--max-train-examples",
      parserFlag: "--train-examples"
    },
    {
      commandFlag: "--eval-limit",
      parserFlag: "--eval-limit-per-benchmark"
    },
    {
      commandFlag: "--comparison-contract-json",
      parserFlag: "--comparison-contract"
    },
    {
      commandFlag: "--planned-condition-contract-json",
      parserFlag: "--planned-condition-contract"
    },
    {
      commandFlag: "--num-train-epochs",
      parserFlag: "--epochs"
    },
    {
      commandFlag: "--disable-progress-bars",
      parserFlag: "--disable-progress-bar"
    },
    {
      commandFlag: "--fallback-model",
      parserFlag: "--fallback-base-model"
    },
    {
      commandFlag: "--fallback-model",
      parserFlag: "--fallback-model-id"
    },
    {
      commandFlag: "--base-model",
      parserFlag: "--base-model-id"
    },
    {
      commandFlag: "--base-model",
      parserFlag: "--model-name"
    },
    {
      commandFlag: "--base-model",
      parserFlag: "--model-name-or-path"
    },
    {
      commandFlag: "--baseline-condition",
      parserFlag: "--baseline-condition-marker"
    },
    {
      commandFlag: "--baseline-condition",
      parserFlag: "--baseline-marker"
    },
    {
      commandFlag: "--baseline-condition",
      parserFlag: "--baseline"
    },
    {
      commandFlag: "--baseline-marker",
      parserFlag: "--baseline-condition-marker"
    },
    {
      commandFlag: "--baseline-marker",
      parserFlag: "--baseline_condition_marker"
    },
    {
      commandFlag: "--baseline-marker",
      parserFlag: "--baseline-condition"
    },
    {
      commandFlag: "--baseline-marker",
      parserFlag: "--baseline"
    }
  ].filter((pair) => commandFlags.has(pair.commandFlag));
  const runtimeOptions = [
    {
      commandFlag: "--metrics-path",
      line: "parser.add_argument('--metrics-path', default='metrics.json', help='AutoLabOS metrics JSON output path.')"
    },
    {
      commandFlag: "--public-dir",
      line: "parser.add_argument('--public-dir', default='.', help='Public AutoLabOS experiment artifact directory.')"
    },
    {
      commandFlag: "--run-artifact-dir",
      line: "parser.add_argument('--run-artifact-dir', default='.', help='Private AutoLabOS run artifact directory.')"
    },
    {
      commandFlag: "--base-model",
      line: "parser.add_argument('--base-model', default=None, help='Base model identifier supplied by AutoLabOS.')"
    },
    {
      commandFlag: "--fallback-base-model",
      line: "parser.add_argument('--fallback-base-model', default=None, help='Fallback model identifier supplied by AutoLabOS.')"
    },
    {
      commandFlag: "--condition-markers",
      line: "parser.add_argument('--condition-markers', default=None, help='Comma-separated planned condition markers supplied by AutoLabOS.')"
    },
    {
      commandFlag: "--budget-timeout-sec",
      line: "parser.add_argument('--budget-timeout-sec', dest='timeout_sec', type=float, default=None, help='AutoLabOS execution budget in seconds for runner compatibility.')"
    },
    {
      commandFlag: "--locked-budget-timeout-sec",
      line: "parser.add_argument('--locked-budget-timeout-sec', dest='timeout_sec', type=float, default=None, help='Locked AutoLabOS execution budget in seconds for runner compatibility.')"
    }
  ].filter((option) => commandFlags.has(option.commandFlag));

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (!/\bargparse\b/u.test(source) || !/\badd_argument\s*\(/u.test(source)) {
    return { repaired: false };
  }

  const acceptedFlagsForDynamicAliases = extractPythonArgparseLongFlags(source);
  const normalizeFlagToken = (token: string): string => {
    const lower = token.toLowerCase();
    if (lower.endsWith("ies") && lower.length > 4) {
      return `${lower.slice(0, -3)}y`;
    }
    if (lower.endsWith("ses") && lower.length > 4) {
      return lower.slice(0, -2);
    }
    if (lower.endsWith("s") && lower.length > 3) {
      return lower.slice(0, -1);
    }
    return lower;
  };
  const flagTokens = (flag: string): string[] =>
    flag
      .replace(/^--/u, "")
      .split("-")
      .map(normalizeFlagToken)
      .filter(Boolean);
  const parserFlagMatchesPluralSchedulerFlag = (commandFlag: string, parserFlag: string): boolean => {
    if (parserFlag === commandFlag || !/^--[a-z0-9][a-z0-9-]*s$/iu.test(commandFlag)) {
      return false;
    }
    const commandTokens = flagTokens(commandFlag);
    const parserTokens = flagTokens(parserFlag);
    const commandSubject = commandTokens.at(-1);
    const parserSubject = parserTokens.at(-1);
    if (!commandSubject) {
      return false;
    }
    if (parserSubject === commandSubject && parserFlag.endsWith("s")) {
      return true;
    }
    return parserTokens.includes(commandSubject) && parserTokens.some((token) => ["list", "set", "ids", "collection"].includes(token));
  };
  for (const commandFlag of [...commandFlags].sort()) {
    if (acceptedFlagsForDynamicAliases.has(commandFlag)) {
      continue;
    }
    const parserFlag = [...acceptedFlagsForDynamicAliases]
      .sort()
      .find((flag) => parserFlagMatchesPluralSchedulerFlag(commandFlag, flag));
    if (parserFlag && !aliasPairs.some((pair) => pair.commandFlag === commandFlag && pair.parserFlag === parserFlag)) {
      aliasPairs.push({ commandFlag, parserFlag });
    }
  }

  if (aliasPairs.length === 0 && runtimeOptions.length === 0) {
    return { repaired: false };
  }

  let nextSource = source;
  const addedAliases: string[] = [];
  for (const { commandFlag, parserFlag } of aliasPairs) {
    if (
      extractPythonArgparseLongFlags(nextSource).has(commandFlag) &&
      pythonArgparseFlagHasDestination(nextSource, commandFlag, argparseDestinationForLongFlag(parserFlag))
    ) {
      continue;
    }
    const lines = nextSource.split(/\r?\n/u);
    for (let index = 0; index < lines.length; index += 1) {
      if (!/\badd_argument\s*\(/u.test(lines[index])) {
        continue;
      }
      const call = extractPythonCallExpression(lines, index);
      if (
        !call ||
        !new RegExp(`["']${escapeRegExpLiteral(parserFlag)}["']`, "u").test(call.text) ||
        new RegExp(`["']${escapeRegExpLiteral(commandFlag)}["']`, "u").test(call.text)
      ) {
        continue;
      }

      const parserFlagPattern = new RegExp(`(["']${escapeRegExpLiteral(parserFlag)}["'])`, "u");
      const repairedCall = call.text.replace(parserFlagPattern, `$1, "${commandFlag}"`);
      if (repairedCall !== call.text) {
        nextSource = nextSource.replace(call.text, repairedCall);
        addedAliases.push(`${commandFlag}->${parserFlag}`);
      }
      break;
    }
  }

  const addedRuntimeOptions: string[] = [];
  for (const { commandFlag, line } of runtimeOptions) {
    if (extractPythonArgparseLongFlags(nextSource).has(commandFlag)) {
      continue;
    }
    const returnParserPattern = /^(\s*)return\s+parser\s*$/mu;
    if (!returnParserPattern.test(nextSource)) {
      continue;
    }
    nextSource = nextSource.replace(
      returnParserPattern,
      (_match, indent: string) => [`${indent}${line}`, `${indent}return parser`].join("\n")
    );
    addedRuntimeOptions.push(commandFlag);
  }

  if (nextSource === source || (addedAliases.length === 0 && addedRuntimeOptions.length === 0)) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  const repairSummary = [
    addedAliases.length > 0 ? `alias(es) ${addedAliases.join(", ")}` : "",
    addedRuntimeOptions.length > 0 ? `runtime option(s) ${addedRuntimeOptions.join(", ")}` : ""
  ]
    .filter(Boolean)
    .join("; ");
  return {
    repaired: true,
    message: `Added run_command argparse ${repairSummary} to ${path.basename(scriptPath)} before handoff.`
  };
}

async function repairPythonCallFlexiblyDuplicateArgsKeywords(
  scriptPath?: string
): Promise<{ repaired: boolean; message?: string }> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (!/\b_call_flexibly\s*\(/u.test(source)) {
    return { repaired: false };
  }

  const nextSource = source.replace(
    /_call_flexibly\(\s*([A-Za-z_][A-Za-z0-9_]*)\s*,\s*args\s*,\s*parser\s*,\s*args\s*=\s*args\s*,\s*parser\s*=\s*parser\s*\)/gu,
    "_call_flexibly($1, args, parser)"
  );
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Removed duplicate positional/keyword args from _call_flexibly in ${path.basename(scriptPath)} before handoff.`
  };
}

function extractPythonArgparseLongFlags(source: string): Set<string> {
  const flags = new Set<string>();
  for (const match of source.matchAll(/\badd_argument\s*\(([\s\S]*?)\)/gu)) {
    const argsText = match[1] || "";
    for (const flagMatch of argsText.matchAll(/["'](--[A-Za-z0-9][A-Za-z0-9_-]*)["']/gu)) {
      flags.add(flagMatch[1]);
    }
  }
  return flags;
}

function pythonArgparseFlagHasDestination(source: string, flag: string, destination: string): boolean {
  for (const match of source.matchAll(/\badd_argument\s*\(([\s\S]*?)\)/gu)) {
    const argsText = match[1] || "";
    if (!new RegExp(`["']${escapeRegExpLiteral(flag)}["']`, "u").test(argsText)) {
      continue;
    }
    const explicitDest = argsText.match(/\bdest\s*=\s*["']([^"']+)["']/u)?.[1];
    if (explicitDest === destination) {
      return true;
    }
    if (explicitDest) {
      continue;
    }
    const firstLongFlag = argsText.match(/["'](--[A-Za-z0-9][A-Za-z0-9_-]*)["']/u)?.[1];
    if (firstLongFlag && argparseDestinationForLongFlag(firstLongFlag) === destination) {
      return true;
    }
  }
  return false;
}

function argparseDestinationForLongFlag(flag: string): string {
  return flag.replace(/^--/u, "").replace(/-/gu, "_");
}

function extractPythonArgparseNoValueLongFlags(source: string): Set<string> {
  const flags = new Set<string>();
  for (const match of source.matchAll(/\badd_argument\s*\(([\s\S]*?)\)/gu)) {
    const argsText = match[1] || "";
    if (!/\baction\s*=\s*["'](?:store_true|store_false|store_const|append_const|count)["']/u.test(argsText)) {
      continue;
    }
    for (const flagMatch of argsText.matchAll(/["'](--[A-Za-z0-9][A-Za-z0-9_-]*)["']/gu)) {
      flags.add(flagMatch[1]);
    }
  }
  return flags;
}

function extractLongOptionFlags(command: string): string[] {
  const flags: string[] = [];
  const tokens = command.match(/"[^"]*"|'[^']*'|\S+/g) || [];
  for (const token of tokens) {
    const flag = unquoteShellToken(token || "").split("=", 2)[0] || "";
    if (!/^--[A-Za-z0-9][A-Za-z0-9_-]*$/u.test(flag)) {
      continue;
    }
    if (flag === "--help" || flags.includes(flag)) {
      continue;
    }
    flags.push(flag);
  }
  return flags;
}

function extractLongOptionFlagsWithValues(command: string): string[] {
  const flags: string[] = [];
  const tokens = command.match(/"[^"]*"|'[^']*'|\S+/g) || [];
  for (let index = 0; index < tokens.length; index += 1) {
    const token = unquoteShellToken(tokens[index] || "");
    if (!/^--[A-Za-z0-9][A-Za-z0-9_-]*/u.test(token)) {
      continue;
    }
    const [flag, inlineValue] = token.split("=", 2);
    const next = unquoteShellToken(tokens[index + 1] || "");
    const hasValue = inlineValue !== undefined || (next.length > 0 && !next.startsWith("-"));
    if (hasValue && flag !== "--help" && !flags.includes(flag)) {
      flags.push(flag);
    }
  }
  return flags;
}

export async function repairPythonExperimentConfigMetadataSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (!source.includes("class ExperimentConfig:")) {
    return { repaired: false };
  }
  if (!source.includes("metadata=")) {
    return { repaired: false };
  }

  const classMatch = [...source.matchAll(/^class ExperimentConfig:\s*$/gmu)].find(
    (match) => !isLikelyInsidePythonTripleQuotedString(source, match.index ?? 0)
  );
  if (!classMatch) {
    return { repaired: false };
  }
  const classLineEnd = source.indexOf("\n", classMatch.index);
  if (classLineEnd < 0) {
    return { repaired: false };
  }
  const bodyStart = classLineEnd + 1;
  let bodyEnd = source.length;
  const bodyTail = source.slice(bodyStart);
  let offset = bodyStart;
  for (const lineMatch of bodyTail.matchAll(/.*(?:\n|$)/gu)) {
    const line = lineMatch[0] || "";
    if (line.length === 0) {
      break;
    }
    const withoutNewline = line.replace(/\n$/u, "");
    const trimmed = withoutNewline.trim();
    if (trimmed.length > 0 && !withoutNewline.startsWith(" ") && !withoutNewline.startsWith("\t")) {
      bodyEnd = offset;
      break;
    }
    offset += line.length;
  }
  const classBody = source.slice(bodyStart, bodyEnd);
  if (/\n\s+metadata\s*:\s*/u.test(`\n${classBody}`)) {
    return { repaired: false };
  }

  const metadataLine = "    metadata: Dict[str, Any] = field(default_factory=dict)\n";
  let nextBody: string;
  if (/\n\s+comparison_contract\s*:\s*/u.test(`\n${classBody}`)) {
    nextBody = classBody.replace(/\n(\s+comparison_contract\s*:)/u, `\n${metadataLine}$1`);
  } else {
    nextBody = `${classBody}${metadataLine}`;
  }

  const nextSource = ensurePythonDataclassesFieldImport(
    `${source.slice(0, bodyStart)}${nextBody}${source.slice(bodyEnd)}`
  );
  if (nextSource === source) {
    return { repaired: false };
  }
  if (!(await pythonSourceParsesForRepair(nextSource, scriptPath))) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Added an ExperimentConfig.metadata compatibility field to ${path.basename(scriptPath)} before handoff.`
  };
}

export async function repairPythonAdapterRecipeConfigMetadataAliasSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (
    !source.includes("class AdapterRecipeConfig:") ||
    !source.includes("_coerce_recipe_metadata_to_config") ||
    !source.includes("field_aliases") ||
    !source.includes("candidate_id: str") ||
    source.includes("_autolabos_adapter_recipe_config_metadata_alias_marker")
  ) {
    return { repaired: false };
  }

  const aliasNeedle = "        field_aliases: Dict[str, str] = {\n";
  if (!source.includes(aliasNeedle)) {
    return { repaired: false };
  }

  const aliasLines = [
    "            \"candidate_id\": \"recipe_id\",",
    "            \"adapter_method\": \"peft_method\",",
    "            \"train_dataset_name\": \"dataset_name\",",
    "            \"train_dataset_config\": \"dataset_config\",",
    "            \"train_dataset_split\": \"dataset_split\",",
    "            \"train_subset_size\": \"subset_size\",",
    "            \"train_seed\": \"subset_seed\",",
    "            \"enabled\": \"should_train\",",
    "            \"comparison_role\": \"comparison_role\",",
    "            \"adapter_target_modules\": \"target_modules\",",
    "            \"use_adaadapter\": \"use_adaadapter\",",
    "            \"adaadapter_init_r\": \"adaadapter_init_r\",",
    "            \"adaadapter_target_r\": \"adaadapter_target_r\","
  ];

  let nextSource = source.replace(
    aliasNeedle,
    [
      "        _autolabos_adapter_recipe_config_metadata_alias_marker = True",
      aliasNeedle.trimEnd(),
      ...aliasLines
    ].join("\n") + "\n"
  );

  const tupleCoercionPattern =
    /kwargs\[destination\]\s*=\s*complete_metadata\[source\]/u;
  nextSource = nextSource.replace(
    tupleCoercionPattern,
    [
      "kwargs[destination] = (",
      "                    tuple(complete_metadata[source])",
      "                    if destination in {\"adapter_target_modules\", \"modules_to_save\"} and isinstance(complete_metadata[source], list)",
      "                    else complete_metadata[source]",
      "                )"
    ].join("\n")
  );

  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Added AdapterRecipeConfig metadata aliases to ${path.basename(scriptPath)} before handoff.`
  };
}

export async function repairPythonExperimentDefaultsHfRuntimeFieldSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (
    !source.includes("class ExperimentDefaults:") ||
    !source.includes("defaults.trust_remote_code") ||
    !source.includes("DEFAULT_TRUST_REMOTE_CODE")
  ) {
    return { repaired: false };
  }

  const classStart = source.indexOf("class ExperimentDefaults:\n");
  if (classStart < 0) {
    return { repaired: false };
  }
  const bodyStart = classStart + "class ExperimentDefaults:\n".length;
  const nextDecorator = source.indexOf("\n@dataclass", bodyStart);
  const nextDataclassesDecorator = source.indexOf("\n@dataclasses.dataclass", bodyStart);
  const nextClass = source.indexOf("\nclass ", bodyStart);
  const nextDef = source.indexOf("\ndef ", bodyStart);
  const bodyEndCandidates = [nextDecorator, nextDataclassesDecorator, nextClass, nextDef].filter(
    (value) => value >= 0
  );
  const bodyEnd = bodyEndCandidates.length > 0 ? Math.min(...bodyEndCandidates) : source.length;
  const classBody = source.slice(bodyStart, bodyEnd);
  if (/\n\s+trust_remote_code\s*:\s*/u.test(`\n${classBody}`)) {
    return { repaired: false };
  }

  const trustRemoteCodeLine = "    trust_remote_code: bool = DEFAULT_TRUST_REMOTE_CODE\n";
  let nextBody: string;
  if (/\n\s+model_revision\s*:\s*/u.test(`\n${classBody}`)) {
    nextBody = classBody.replace(
      /(\n\s+model_revision\s*:[^\n]*\n)/u,
      `$1${trustRemoteCodeLine}`
    );
  } else if (/\n\s+tokenizer_name\s*:\s*/u.test(`\n${classBody}`)) {
    nextBody = classBody.replace(
      /(\n\s+tokenizer_name\s*:[^\n]*\n)/u,
      `$1${trustRemoteCodeLine}`
    );
  } else {
    nextBody = `${classBody}${trustRemoteCodeLine}`;
  }

  const nextSource = `${source.slice(0, bodyStart)}${nextBody}${source.slice(bodyEnd)}`;
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Added ExperimentDefaults.trust_remote_code to ${path.basename(scriptPath)} before handoff.`
  };
}

