export async function repairPythonCandidateSpecAdapterRecipeNormalizationSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (
    !source.includes("class CandidateSpec") ||
    !source.includes("class AdapterRecipe") ||
    !source.includes("def normalize_adapter_recipe(") ||
    !source.includes("def validate_locked_recipe_order(") ||
    !source.includes("LOCKED_ADAPTER_RECIPES") ||
    !source.includes("candidate 0 must be the unmodified non-trainable base checkpoint") ||
    source.includes("_autolabos_candidate_spec_adapter_recipe_normalization_marker")
  ) {
    return { repaired: false };
  }

  const insertionMatch =
    source.match(/\nLOCKED_ADAPTER_RECIPES\s*:/u) ||
    source.match(/\nLOCKED_ADAPTER_RECIPES\s*=/u);
  if (!insertionMatch || insertionMatch.index === undefined) {
    return { repaired: false };
  }

  const helper = [
    "",
    "def _autolabos_candidate_spec_adapter_recipe_normalization_marker():",
    "    return True",
    "",
    "def normalize_adapter_recipe(raw, expected_order):",
    "    \"\"\"Compatibility normalization for CandidateSpec-backed adapter recipe lists.\"\"\"",
    "    if isinstance(raw, AdapterRecipe):",
    "        values = raw.to_metrics_dict() if hasattr(raw, \"to_metrics_dict\") else dict(getattr(raw, \"__dict__\", {}))",
    "        values[\"target_modules\"] = tuple(values.get(\"target_modules\") or ())",
    "        values[\"expected_order\"] = expected_order",
    "        if str(values.get(\"recipe_type\", \"\")).lower() in {\"unmodified_base\", \"base_model\", \"baseline\", \"none\", \"no_adapter\"}:",
    "            values[\"recipe_type\"] = \"base\"",
    "            values[\"trainable\"] = False",
    "        return AdapterRecipe(**values)",
    "    recipe_id = str(",
    "        _recipe_value(",
    "            raw,",
    "            \"recipe_id\",",
    "            _recipe_value(raw, \"candidate_id\", _recipe_value(raw, \"id\", _recipe_value(raw, \"name\", f\"candidate_{expected_order}\"))),",
    "        )",
    "    )",
    "    raw_type = str(",
    "        _recipe_value(",
    "            raw,",
    "            \"recipe_type\",",
    "            _recipe_value(raw, \"kind\", \"base\" if expected_order == 0 or \"base\" in recipe_id.lower() else \"adapter\"),",
    "        )",
    "    ).lower().replace(\"-\", \"_\")",
    "    if raw_type in {\"unmodified_base\", \"base_model\", \"baseline_base\", \"baseline\", \"none\", \"no_adapter\", \"base\"}:",
    "        recipe_type = \"base\"",
    "    elif expected_order == 0 and (\"base\" in recipe_id.lower() or \"unmodified\" in recipe_id.lower()):",
    "        recipe_type = \"base\"",
    "    elif raw_type in {\"rank_stabilized_adapter\", \"rank_stabilized_adapter\", \"decomposed_adapter\"}:",
    "        recipe_type = \"adapter\"",
    "    else:",
    "        recipe_type = raw_type",
    "    rank = _recipe_value(raw, \"rank\", _recipe_value(raw, \"r\", _recipe_value(raw, \"adapter_r\", None)))",
    "    alpha = _recipe_value(raw, \"alpha\", _recipe_value(raw, \"adapter_alpha\", None))",
    "    dropout = float(_recipe_value(raw, \"dropout\", _recipe_value(raw, \"adapter_dropout\", 0.0)) or 0.0)",
    "    target_modules = _coerce_target_modules(_recipe_value(raw, \"target_modules\", None), default=())",
    "    if expected_order == 1 and recipe_type in {\"adapter\", \"quantized_adapter\"}:",
    "        target_modules = (\"target_module_a\", \"target_module_b\", \"target_module_c\", \"target_module_d\")",
    "    elif recipe_type in {\"adapter\", \"quantized_adapter\"} and not target_modules:",
    "        target_modules = (\"target_module_a\", \"target_module_b\", \"target_module_c\", \"target_module_d\")",
    "    trainable_raw = _recipe_value(raw, \"trainable\", None)",
    "    if trainable_raw is None:",
    "        trainable_raw = _recipe_value(raw, \"train\", None)",
    "    trainable = (recipe_type != \"base\") if trainable_raw is None else bool(trainable_raw)",
    "    if recipe_type == \"base\":",
    "        trainable = False",
    "    locked_raw = _recipe_value(raw, \"locked_baseline\", None)",
    "    if locked_raw is None:",
    "        locked_raw = _recipe_value(raw, \"is_locked_tuned_baseline\", None)",
    "    if locked_raw is None:",
    "        locked_raw = _recipe_value(raw, \"is_unmodified_baseline\", None)",
    "    locked_baseline = bool(locked_raw) or expected_order in (0, 1)",
    "    return AdapterRecipe(",
    "        recipe_id=recipe_id,",
    "        display_name=str(_recipe_value(raw, \"display_name\", _recipe_value(raw, \"label\", recipe_id))),",
    "        recipe_type=recipe_type,",
    "        description=str(_recipe_value(raw, \"description\", recipe_id)),",
    "        rank=None if rank is None else int(rank),",
    "        alpha=None if alpha is None else int(alpha),",
    "        dropout=dropout,",
    "        target_modules=target_modules,",
    "        bias=str(_recipe_value(raw, \"bias\", \"none\")),",
    "        task_type=str(_recipe_value(raw, \"task_type\", \"CAUSAL_LM\")),",
    "        trainable=trainable,",
    "        locked_baseline=locked_baseline,",
    "        expected_order=expected_order,",
    "    )",
    ""
  ].join("\n");

  const insertionIndex = insertionMatch.index;
  const nextSource = `${source.slice(0, insertionIndex)}${helper}${source.slice(insertionIndex)}`;
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Aligned CandidateSpec-to-generated recipe normalization in ${path.basename(scriptPath)} before handoff.`
  };
}

export async function repairPythonLockedRecipeCatalogAliasSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (
    source.includes("def get_recipe_registry(") &&
    source.includes("ADAPTER_RECIPES") &&
    source.includes("candidate = globals().get(candidate_name)") &&
    source.includes('"RECIPE_CONFIGS"') &&
    source.includes('"RECIPE_REGISTRY"') &&
    !source.includes('"ADAPTER_RECIPES",')
  ) {
    const candidateTuplePattern =
      /(\s*for candidate_name in \(\n(?:\s*"[^"]+",\n)+\s*\):)/u;
    const candidateTupleMatch = source.match(candidateTuplePattern);
    if (candidateTupleMatch?.[0] && !candidateTupleMatch[0].includes('"ADAPTER_RECIPES"')) {
      const nextTuple = candidateTupleMatch[0].replace(
        /(\s*"RECIPE_REGISTRY",\n)/u,
        `$1        "ADAPTER_RECIPES",\n`
      );
      if (nextTuple !== candidateTupleMatch[0]) {
        await fs.writeFile(scriptPath, source.replace(candidateTupleMatch[0], nextTuple), "utf8");
        return {
          repaired: true,
          message: `Expanded generated recipe registry lookup to ADAPTER_RECIPES in ${path.basename(scriptPath)} before handoff.`
        };
      }
    }
  }

  const narrowCatalogLookupPattern =
    /^(\s*)recipes_obj\s*=\s*globals\(\)\.get\("RECIPE_SPECS",\s*globals\(\)\.get\("RECIPES",\s*None\)\)$/mu;
  if (
    source.includes("def _get_recipe_catalog(") &&
    narrowCatalogLookupPattern.test(source) &&
    /\b(?:ORDERED_RECIPE_SPECS|ALL_RECIPES|LOCKED_ADAPTER_RECIPES|ORDERED_ADAPTER_RECIPES|ADAPTER_RECIPE_SPECS|LIGHTWEIGHT_CANDIDATE_RECIPES|LIGHTWEIGHT_ADAPTER_CANDIDATES)\b/u.test(
      source
    ) &&
    !source.includes("_autolabos_recipe_catalog_lookup_names")
  ) {
    const nextSource = source.replace(narrowCatalogLookupPattern, (_match, indent: string) =>
      [
        `${indent}_autolabos_recipe_catalog_lookup_names = (`,
        `${indent}    "RECIPE_SPECS",`,
        `${indent}    "RECIPES",`,
        `${indent}    "ORDERED_RECIPE_SPECS",`,
        `${indent}    "ALL_RECIPES",`,
        `${indent}    "LOCKED_ADAPTER_RECIPES",`,
        `${indent}    "ORDERED_ADAPTER_RECIPES",`,
        `${indent}    "ADAPTER_RECIPE_SPECS",`,
        `${indent}    "LIGHTWEIGHT_CANDIDATE_RECIPES",`,
        `${indent}    "LIGHTWEIGHT_ADAPTER_CANDIDATES",`,
        `${indent})`,
        `${indent}recipes_obj = None`,
        `${indent}for _autolabos_recipe_catalog_name in _autolabos_recipe_catalog_lookup_names:`,
        `${indent}    _autolabos_recipe_catalog_value = globals().get(_autolabos_recipe_catalog_name)`,
        `${indent}    if _autolabos_recipe_catalog_value:`,
        `${indent}        recipes_obj = _autolabos_recipe_catalog_value`,
        `${indent}        break`
      ].join("\n")
    );
    if (nextSource !== source) {
      await fs.writeFile(scriptPath, nextSource, "utf8");
      return {
        repaired: true,
        message: `Expanded final recipe catalog lookup aliases in ${path.basename(scriptPath)} before handoff.`
      };
    }
  }

  if (
    !source.includes("def locked_recipe_execution_order(") ||
    !source.includes("def _recipe_catalog_from_globals(") ||
    !source.includes("BASELINE_UNMODIFIED_RECIPE_ID") ||
    !(source.includes("STANDARD_TUNED_BASELINE_RECIPE_ID") || source.includes("VANILLA_LORA_BASELINE_RECIPE_ID") || source.includes("LOCKED_LORA_BASELINE_CANDIDATE_ID")) ||
    source.includes("_autolabos_locked_recipe_catalog_alias_marker")
  ) {
    return { repaired: false };
  }

  const catalogRowPattern =
    /return OrderedDict\(\(str\(k\), dict\(v\) if isinstance\(v, Mapping\) else \{"value": v\}\) for k, v in value\.items\(\)\)/u;
  const orderInsertionNeedle = [
    "    for recipe_id in available:",
    "        if recipe_id not in ordered:",
    "            ordered.append(recipe_id)"
  ].join("\n");
  if (!catalogRowPattern.test(source) || !source.includes(orderInsertionNeedle)) {
    return { repaired: false };
  }

  const helperNeedle = source.includes('STANDARD_TUNED_BASELINE_RECIPE_ID = "standard_tuned_baseline"\n')
    ? 'STANDARD_TUNED_BASELINE_RECIPE_ID = "standard_tuned_baseline"\n'
    : source.includes('VANILLA_LORA_BASELINE_RECIPE_ID = "vanilla_adapter_baseline"\n')
      ? 'VANILLA_LORA_BASELINE_RECIPE_ID = "vanilla_adapter_baseline"\n'
      : source.includes('LOCKED_LORA_BASELINE_CANDIDATE_ID = "locked_candidate_condition"\n')
        ? 'LOCKED_LORA_BASELINE_CANDIDATE_ID = "locked_candidate_condition"\n'
        : "";
  if (!source.includes(helperNeedle)) {
    return { repaired: false };
  }

  const helper = [
    "",
    "def _autolabos_locked_recipe_catalog_alias_marker():",
    "    return True",
    "",
    "def _autolabos_recipe_catalog_row(recipe_id, raw, expected_order):",
    "    \"\"\"Normalize dataclass- or mapping-backed recipe registries without changing execution IDs.\"\"\"",
    "    if isinstance(raw, Mapping):",
    "        row = dict(raw)",
    "    elif hasattr(raw, \"__dict__\"):",
    "        row = dict(getattr(raw, \"__dict__\", {}))",
    "    else:",
    "        row = {\"value\": raw}",
    "    effective_id = str(row.get(\"recipe_id\") or row.get(\"candidate_id\") or row.get(\"id\") or recipe_id)",
    "    row.setdefault(\"recipe_id\", effective_id)",
    "    row.setdefault(\"candidate_id\", effective_id)",
    "    lowered = effective_id.lower().replace(\"-\", \"_\")",
    "    family = str(row.get(\"family\", row.get(\"peft_type\", row.get(\"recipe_type\", \"\")))).lower().replace(\"-\", \"_\")",
    "    if expected_order == 0 or (\"unmodified\" in lowered and \"base\" in lowered) or family in {\"base_model_reference\", \"base\", \"none\", \"no_adapter\"}:",
    "        row[\"is_unmodified_base\"] = True",
    "        row.setdefault(\"peft_type\", \"none\")",
    "        row.setdefault(\"train\", False)",
    "    if expected_order == 1 or ((\"adapter\" in lowered or family in {\"adapter\", \"rank_stabilized_adapter\"}) and \"baseline\" in lowered) or bool(row.get(\"is_locked_baseline\")):",
    "        row[\"is_locked_baseline\"] = True",
    "        row.setdefault(\"peft_type\", \"adapter\")",
    "        row.setdefault(\"train\", True)",
    "    return row",
    "",
    "def _autolabos_recipe_is_unmodified_base(recipe_id, config):",
    "    lowered = str(config.get(\"recipe_id\", config.get(\"candidate_id\", recipe_id))).lower().replace(\"-\", \"_\")",
    "    peft_type = str(config.get(\"peft_type\", config.get(\"recipe_type\", \"\"))).lower().replace(\"-\", \"_\")",
    "    family = str(config.get(\"family\", \"\")).lower().replace(\"-\", \"_\")",
    "    return bool(config.get(\"is_unmodified_base\")) or (\"unmodified\" in lowered and \"base\" in lowered) or peft_type in {\"none\", \"base\", \"no_adapter\"} or family == \"base_model_reference\"",
    "",
    "def _autolabos_recipe_is_locked_tuned_baseline(recipe_id, config):",
    "    lowered = str(config.get(\"recipe_id\", config.get(\"candidate_id\", recipe_id))).lower().replace(\"-\", \"_\")",
    "    peft_type = str(config.get(\"peft_type\", config.get(\"recipe_type\", \"\"))).lower().replace(\"-\", \"_\")",
    "    family = str(config.get(\"family\", \"\")).lower().replace(\"-\", \"_\")",
    "    return bool(config.get(\"is_locked_baseline\")) or ((\"adapter\" in lowered or peft_type in {\"adapter\", \"rank_stabilized_adapter\"} or family in {\"adapter\", \"rank_stabilized_adapter\"}) and \"baseline\" in lowered)",
    ""
  ].join("\n");

  let nextSource = source.replace(helperNeedle, `${helperNeedle}${helper}`);
  nextSource = nextSource.replace(
    catalogRowPattern,
    "return OrderedDict((str(k), _autolabos_recipe_catalog_row(str(k), v, _autolabos_idx)) for _autolabos_idx, (k, v) in enumerate(value.items()))"
  );

  const dynamicAliasBlock = [
    "    if not any(_autolabos_recipe_is_unmodified_base(recipe_id, catalog.get(recipe_id, {})) for recipe_id in ordered):",
    "        for recipe_id in available:",
    "            if recipe_id not in ordered and _autolabos_recipe_is_unmodified_base(recipe_id, catalog.get(recipe_id, {})):",
    "                ordered.append(recipe_id)",
    "                break",
    "    if not any(_autolabos_recipe_is_locked_tuned_baseline(recipe_id, catalog.get(recipe_id, {})) for recipe_id in ordered):",
    "        for recipe_id in available:",
    "            if recipe_id not in ordered and _autolabos_recipe_is_locked_tuned_baseline(recipe_id, catalog.get(recipe_id, {})):",
    "                ordered.append(recipe_id)",
    "                break",
    "",
    orderInsertionNeedle
  ].join("\n");
  nextSource = nextSource.replace(orderInsertionNeedle, dynamicAliasBlock);

  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Aligned locked recipe catalog aliases with generated baseline-first IDs in ${path.basename(scriptPath)} before handoff.`
  };
}

async function repairPythonBaselineFirstRecipeOrderSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (!/COMPARISON_MODE\s*=\s*["']baseline_first_locked["']/u.test(source) && !/BASELINE_FIRST_REQUIRED\s*=\s*True/u.test(source)) {
    return { repaired: false };
  }
  if (!source.includes("def _candidate_sort_key(") || !source.includes("def _get_locked_recipe_sequence(")) {
    return { repaired: false };
  }
  if (!source.includes("Locked comparison contract requires the untuned reference candidate to run first.")) {
    return { repaired: false };
  }

  const sortKeyPattern =
    /def _candidate_sort_key\(recipe: Any\) -> Tuple\[int, str\]:\n(?:    .*\n)+?(?=\ndef _get_locked_recipe_sequence\()/u;
  const nextSortKey = [
    "def _candidate_sort_key(recipe: Any) -> Tuple[int, str]:",
    "    recipe_id = _recipe_identifier(recipe)",
    "    standard_id = _standard_adapter_id().lower()",
    "    recipe_id_lower = recipe_id.lower()",
    "    if recipe_id_lower == standard_id or (\"standard\" in recipe_id_lower and \"adapter\" in recipe_id_lower):",
    "        return (0, recipe_id)",
    "    if _recipe_is_reference(recipe):",
    "        return (1, recipe_id)",
    "    return (2, recipe_id)",
    ""
  ].join("\n");

  const sequenceValidationPattern =
    /    recipes = sorted\(recipes, key=_candidate_sort_key\)\n    if not _recipe_is_reference\(recipes\[0\]\):\n        raise RuntimeError\(\n            "Locked comparison contract requires the untuned reference candidate to run first\."\n        \)\n    if len\(recipes\) > 1:\n        second_id = _recipe_identifier\(recipes\[1\]\)\.lower\(\)\n        expected_adapter = _standard_adapter_id\(\)\.lower\(\)\n        if second_id != expected_adapter and not \("standard" in second_id and "adapter" in second_id\):\n            raise RuntimeError\(\n                "Locked comparison contract requires the standard adapter tuned baseline to run immediately after the reference\."\n            \)\n    return recipes/u;
  const nextSequenceValidation = [
    "    recipes = sorted(recipes, key=_candidate_sort_key)",
    "    first_id = _recipe_identifier(recipes[0]).lower()",
    "    expected_adapter = _standard_adapter_id().lower()",
    "    if first_id != expected_adapter and not (\"standard\" in first_id and \"adapter\" in first_id):",
    "        raise RuntimeError(",
    "            \"Locked baseline-first contract requires the standard adapter tuned baseline to run first.\"",
    "        )",
    "    if len(recipes) > 1 and not any(_recipe_is_reference(recipe) for recipe in recipes):",
    "        raise RuntimeError(",
    "            \"Locked baseline-first contract requires the untuned reference candidate to remain in the comparison.\"",
    "        )",
    "    return recipes"
  ].join("\n");

  let nextSource = source.replace(sortKeyPattern, nextSortKey);
  nextSource = nextSource.replace(sequenceValidationPattern, nextSequenceValidation);

  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Aligned baseline-first adapter recipe ordering in ${path.basename(scriptPath)} before handoff.`
  };
}

export async function repairPythonBroaderTargetAdapterMarkerSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  const lockedComparison =
    /COMPARISON_MODE\s*=\s*["']baseline_first_locked["']/u.test(source) ||
    /BASELINE_FIRST_REQUIRED\s*=\s*True/u.test(source) ||
    /LOCKED_BASELINE_FIRST_ORDER/u.test(source);
  if (!lockedComparison || !source.includes("broader-target adapter comparator")) {
    return { repaired: false };
  }

  const hasBroaderTargetEvidence =
    /BROADER_TARGET_LORA_RECIPE_ID/u.test(source) ||
    /Broader-target adapter/iu.test(source) ||
    /BROADER_LORA_TARGET_MODULES/u.test(source) ||
    /qkvo|mlp|all_linear|expanded/iu.test(source);
  if (!hasBroaderTargetEvidence) {
    return { repaired: false };
  }

  let nextSource = source;
  nextSource = nextSource.replace(
    /if "r16" in rid and "broad" not in rid:\n        return 1/u,
    [
      "if \"r16\" in rid and not any(",
      "        marker in rid for marker in (\"broad\", \"broader\", \"mlp\", \"qkvo\", \"all_linear\", \"expanded\")",
      "    ):",
      "        return 1"
    ].join("\n")
  );
  nextSource = nextSource.replace(
    /if "broad" in rid or "all_linear" in rid or "broader" in rid:\n        return 3/u,
    "if any(marker in rid for marker in (\"broad\", \"broader\", \"mlp\", \"qkvo\", \"all_linear\", \"expanded\")):\n        return 3"
  );
  nextSource = nextSource.replace(
    /missing = \[label for marker, label in required_markers\.values\(\) if marker not in present\]/u,
    [
      "marker_aliases = {",
      "            \"condition_b\": (\"condition_b\", \"locked_candidate\", \"standard\", \"baseline\"),",
      "            \"broad\": (\"broad\", \"broader\", \"mlp\", \"qkvo\", \"all_linear\", \"expanded\", \"extended\", \"condition_extended\"),",
      "        }",
      "        missing = [",
      "            label",
      "            for marker, label in required_markers.values()",
      "            if not any(alias in present for alias in marker_aliases.get(marker, (marker,)))",
      "        ]"
    ].join("\n")
  );

  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Aligned broader-target adapter marker aliases in ${path.basename(scriptPath)} before handoff.`
  };
}

export async function repairPythonLockedStandardAdapterBaselineIdSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  const lockedComparison =
    /COMPARISON_MODE\s*=\s*["']baseline_first_locked["']/u.test(source) ||
    /BASELINE_FIRST_REQUIRED\s*=\s*True/u.test(source) ||
    /LOCKED_COMPARISON_CONTRACT/u.test(source);
  if (!lockedComparison) {
    return { repaired: false };
  }

  const standardIdMatch = source.match(/\bSTANDARD_LORA_BASELINE_ID\s*=\s*["']([^"']+)["']/u);
  const lockedIdMatch = source.match(/\bLOCKED_STANDARD_LORA_BASELINE_ID\s*=\s*["']([^"']+)["']/u);
  if (!standardIdMatch || !lockedIdMatch) {
    return { repaired: false };
  }

  const standardId = standardIdMatch[1];
  const lockedId = lockedIdMatch[1];
  if (!standardId || !lockedId || standardId === lockedId) {
    return { repaired: false };
  }

  const standardIdAppearsAsRecipe =
    new RegExp(`\\b(recipe_id|id|name)\\s*=\\s*["']${escapeRegex(standardId)}["']`, "u").test(source) ||
    new RegExp(`["']${escapeRegex(standardId)}["']`, "u").test(source);
  if (!standardIdAppearsAsRecipe || !/standard[_-]?adapter/iu.test(standardId)) {
    return { repaired: false };
  }

  const lockedAssignmentPattern =
    /\bLOCKED_STANDARD_LORA_BASELINE_ID\s*=\s*["'][^"']+["']/u;
  const nextSource = source.replace(
    lockedAssignmentPattern,
    "LOCKED_STANDARD_LORA_BASELINE_ID = STANDARD_LORA_BASELINE_ID"
  );
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Aligned locked standard adapter baseline id from ${lockedId} to ${standardId} in ${path.basename(
      scriptPath
    )} before handoff.`
  };
}

export async function repairPythonLegacyBaseModelRecipeIdSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (
    !source.includes("base_model") ||
    !source.includes("Unknown recipe ID(s)") ||
    !source.includes("_normalize_recipe_ids")
  ) {
    return { repaired: false };
  }

  const baselineCandidateMatch = source.match(/\bBASELINE_CANDIDATE_ID\s*=\s*["']([^"']+)["']/u);
  const baselineCandidateId = baselineCandidateMatch?.[1]?.trim();
  if (!baselineCandidateId || baselineCandidateId === "base_model") {
    return { repaired: false };
  }

  const baselineAppearsInRegistry =
    new RegExp(`\\b(recipe_id|id|name)\\s*=\\s*["']${escapeRegex(baselineCandidateId)}["']`, "u").test(source) ||
    new RegExp(`["']${escapeRegex(baselineCandidateId)}["']`, "u").test(source);
  if (!baselineAppearsInRegistry) {
    return { repaired: false };
  }

  const nextSource = source.replace(/(["'])base_model\1/gu, "BASELINE_CANDIDATE_ID");
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Aligned legacy base_model recipe id to ${baselineCandidateId} in ${path.basename(scriptPath)} before handoff.`
  };
}

async function detectPythonBaselineFirstTunedBaselineMismatch(scriptPath?: string): Promise<string | undefined> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return undefined;
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return undefined;
  }

  const lockedComparison =
    /COMPARISON_MODE\s*=\s*["']baseline_first_locked["']/u.test(source) ||
    /BASELINE_FIRST_REQUIRED\s*=\s*True/u.test(source) ||
    /["']comparison_mode["']\s*:\s*["']baseline_first_locked["']/u.test(source) ||
    /["']baseline_first_required["']\s*:\s*True/u.test(source);
  if (!lockedComparison) {
    return undefined;
  }

  const hasUntunedPrimaryBaseline =
    /\bRecipe\s*\(\s*name\s*=\s*["']baseline_no_tuning["'][\s\S]{0,180}\bkind\s*=\s*["']baseline["']/u.test(source) ||
    /\bbaseline\s*=\s*next\s*\([\s\S]{0,400}\.recipe\s*==\s*["']baseline_no_tuning["']/u.test(source) ||
    /\bbaseline_mean_[A-Za-z0-9_]*\s*=\s*baseline\./u.test(source);
  const hasTunedAdapterCandidate = /\badapter_r(?:8|16|32)\b/u.test(source) || /standard[_-]?adapter/iu.test(source) || /candidate_condition_[a-z0-9_]*[\s\S]{0,220}kind\s*[:=]\s*["']adapter["']/iu.test(source);
  if (!hasUntunedPrimaryBaseline || !hasTunedAdapterCandidate) {
    return undefined;
  }

  return [
    "Generated baseline_first_locked adapter runner treats the untuned/no-tuning reference as the primary baseline.",
    "The governed experiment contract requires the tuned standard adapter baseline to be the primary comparator; untuned/no-tuning may be retained only as a reference row.",
    "Revise the runner so baseline metrics and delta/objective comparisons are computed against the named tuned adapter baseline, not baseline_no_tuning."
  ].join(" ");
}

async function repairPythonTransformersSetSeedAliasSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  let nextSource: string | undefined;
  const needsSetSeedAlias = /\bset_seed\s*\(/u.test(source) && !/\n\s*set_seed\s*=/u.test(source);
  if (needsSetSeedAlias) {
    if (/\btransformers_set_seed\b/u.test(source)) {
      const aliasInsertionPattern = /(\n\s*transformers_set_seed\s*=\s*None[^\n]*\n[\s\S]*?_record_optional_dependency\(\s*\n\s*OPTIONAL_DEPENDENCIES,\s*\n\s*["']transformers["'],[\s\S]*?\n\s*\)\s*\n)(\ntry:)/u;
      if (aliasInsertionPattern.test(source)) {
        nextSource = source.replace(aliasInsertionPattern, "$1\nset_seed = transformers_set_seed  # compatibility alias for generated seed helpers\n$2");
      } else {
        const seedHelperMatch = source.match(/\ndef\s+seed_everything\s*\(/u);
        if (seedHelperMatch?.index != null) {
          nextSource = `${source.slice(0, seedHelperMatch.index)}\nset_seed = transformers_set_seed  # compatibility alias for generated seed helpers\n${source.slice(seedHelperMatch.index)}`;
        }
      }
    } else {
      const seedHelperMatch = source.match(/\ndef\s+seed_everything\s*\(/u);
      if (seedHelperMatch?.index != null) {
        const shim = [
          "",
          "try:",
          "    from transformers import set_seed",
          "except Exception:",
          "    set_seed = None",
          ""
        ].join("\n");
        nextSource = `${source.slice(0, seedHelperMatch.index)}${shim}${source.slice(seedHelperMatch.index)}`;
      }
    }
  }

  let sourceAfterSeedAliasRepair = nextSource || source;
  for (const aliasName of ["set_global_seed", "set_all_seeds", "set_reproducible_seed"]) {
    const needsSeedAlias =
      new RegExp(`\\b${escapeRegex(aliasName)}\\s*\\(`, "u").test(sourceAfterSeedAliasRepair) &&
      !new RegExp(`^\\s*def\\s+${escapeRegex(aliasName)}\\s*\\(`, "mu").test(sourceAfterSeedAliasRepair) &&
      !new RegExp(`^\\s*${escapeRegex(aliasName)}\\s*=`, "mu").test(sourceAfterSeedAliasRepair);
    if (!needsSeedAlias) {
      continue;
    }
    const hasSeedFallback =
      /\bdef\s+seed_everything\s*\(/u.test(sourceAfterSeedAliasRepair) ||
      /\bdef\s+setup_runtime\s*\(/u.test(sourceAfterSeedAliasRepair) ||
      /\bdef\s+set_reproducibility\s*\(/u.test(sourceAfterSeedAliasRepair) ||
      /\bdef\s+set_reproducibility_seed\s*\(/u.test(sourceAfterSeedAliasRepair) ||
      /\bdef\s+set_global_seed\s*\(/u.test(sourceAfterSeedAliasRepair) ||
      /\btransformers_set_seed\b/u.test(sourceAfterSeedAliasRepair) ||
      /\bhf_set_seed\b/u.test(sourceAfterSeedAliasRepair) ||
      /\bset_seed\s*=/u.test(sourceAfterSeedAliasRepair) ||
      pythonSourceDefinesOrImportsName(sourceAfterSeedAliasRepair, "set_seed");
    if (hasSeedFallback) {
      const preferredHelper =
        aliasName === "set_all_seeds"
          ? "set_global_seed"
          : aliasName === "set_reproducible_seed"
            ? "set_reproducibility"
            : "seed_everything";
      const seedHelperNames = dedupeStrings([
        preferredHelper,
        "seed_everything",
        "setup_runtime",
        "set_reproducibility",
        "set_reproducibility_seed",
        "set_global_seed"
      ]).filter((name) => name !== aliasName);
      const seedHelperExpression = seedHelperNames
        .map((name) => `globals().get("${name}")`)
        .join(" or ") || "None";
      const shim = [
        "",
        `def ${aliasName}(seed: int) -> None:`,
        `    seed_helper = ${seedHelperExpression}`,
        "    if seed_helper is not None:",
        "        seed_helper(seed)",
        "        return",
        "    transformers_seed = globals().get(\"transformers_set_seed\") or globals().get(\"hf_set_seed\") or globals().get(\"set_seed\")",
        "    if transformers_seed is not None:",
        "        transformers_seed(seed)",
        ""
      ].join("\n");
      const insertionMatch =
        sourceAfterSeedAliasRepair.match(/\ndef\s+main\s*\(/u) ||
        sourceAfterSeedAliasRepair.match(/\ndef\s+run_and_write_metrics\s*\(/u) ||
        sourceAfterSeedAliasRepair.match(/\nif\s+__name__\s*==\s*["']__main__["']/u);
      if (insertionMatch?.index != null) {
        nextSource = `${sourceAfterSeedAliasRepair.slice(0, insertionMatch.index)}${shim}${sourceAfterSeedAliasRepair.slice(insertionMatch.index)}`;
        sourceAfterSeedAliasRepair = nextSource;
      }
    }
  }

  if (!nextSource || nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Aligned generated seed helper compatibility in ${path.basename(scriptPath)} before handoff.`
  };
}

function wrapPythonJsonFirstArgumentWithAutolabosSafe(line: string): string {
  const callMatch = line.match(/\bjson\.dumps?\s*\(/u);
  if (!callMatch || callMatch.index == null) {
    return line;
  }

  const openParenIndex = line.indexOf("(", callMatch.index);
  if (openParenIndex < 0) {
    return line;
  }

  let cursor = openParenIndex + 1;
  while (cursor < line.length && /\s/u.test(line[cursor])) {
    cursor += 1;
  }
  if (line.slice(cursor).startsWith("_autolabos_json_safe(")) {
    return line;
  }

  let parenDepth = 0;
  let bracketDepth = 0;
  let braceDepth = 0;
  let quote: "'" | "\"" | undefined;
  let escaped = false;
  let firstArgumentEnd = -1;

  for (let index = cursor; index < line.length; index += 1) {
    const char = line[index];

    if (quote) {
      if (escaped) {
        escaped = false;
        continue;
      }
      if (char === "\\") {
        escaped = true;
        continue;
      }
      if (char === quote) {
        quote = undefined;
      }
      continue;
    }

    if (char === "'" || char === "\"") {
      quote = char;
      continue;
    }
    if (char === "(") {
      parenDepth += 1;
      continue;
    }
    if (char === ")") {
      if (parenDepth === 0 && bracketDepth === 0 && braceDepth === 0) {
        firstArgumentEnd = index;
        break;
      }
      parenDepth = Math.max(0, parenDepth - 1);
      continue;
    }
    if (char === "[") {
      bracketDepth += 1;
      continue;
    }
    if (char === "]") {
      bracketDepth = Math.max(0, bracketDepth - 1);
      continue;
    }
    if (char === "{") {
      braceDepth += 1;
      continue;
    }
    if (char === "}") {
      braceDepth = Math.max(0, braceDepth - 1);
      continue;
    }
    if (char === "," && parenDepth === 0 && bracketDepth === 0 && braceDepth === 0) {
      firstArgumentEnd = index;
      break;
    }
  }

  if (firstArgumentEnd <= cursor) {
    return line;
  }

  const firstArgument = line.slice(cursor, firstArgumentEnd).trim();
  if (!firstArgument || firstArgument.startsWith("_autolabos_json_safe(")) {
    return line;
  }

  return `${line.slice(0, cursor)}_autolabos_json_safe(${line.slice(cursor, firstArgumentEnd)})${line.slice(firstArgumentEnd)}`;
}

async function repairPythonStrictJsonMetricsSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (!/\bjson\.dumps?\s*\(/u.test(source)) {
    return { repaired: false };
  }

  let nextSource = source;
  let strengthenedJsonSafe = false;
  if (
    /\ndef\s+_autolabos_json_safe\s*\(\s*value\s*\):/u.test(nextSource) &&
    !/value\.strip\(\)\.lower\(\)\s+in\s+\{['"]nan['"]/u.test(nextSource)
  ) {
    nextSource = nextSource.replace(
      /(\ndef\s+_autolabos_json_safe\s*\(\s*value\s*\):\n)/u,
      [
        "$1",
        "    if isinstance(value, str) and value.strip().lower() in {'nan', 'inf', '+inf', '-inf', 'infinity', '+infinity', '-infinity'}:",
        "        return None",
      ].join("\n") + "\n"
    );
    strengthenedJsonSafe = true;
  }
  if (!/\ndef\s+_autolabos_json_safe\s*\(/u.test(nextSource)) {
    const helper = [
      "",
      "def _autolabos_json_safe(value):",
      "    if isinstance(value, str) and value.strip().lower() in {'nan', 'inf', '+inf', '-inf', 'infinity', '+infinity', '-infinity'}:",
      "        return None",
      "    if isinstance(value, dict):",
      "        return {str(key): _autolabos_json_safe(item) for key, item in value.items()}",
      "    if isinstance(value, (list, tuple)):",
      "        return [_autolabos_json_safe(item) for item in value]",
      "    if hasattr(value, '__fspath__'):",
      "        return str(value)",
      "    module_name = value.__class__.__module__",
      "    if isinstance(value, float) or module_name.startswith(('numpy', 'torch')):",
      "        try:",
      "            numeric = float(value)",
      "        except (TypeError, ValueError):",
      "            return None",
      "        if numeric != numeric or numeric in (float('inf'), float('-inf')):",
      "            return None",
      "        return numeric if module_name.startswith(('numpy', 'torch')) else value",
      "    return value",
      ""
    ].join("\n");
    const writeJsonMatch = nextSource.match(/\ndef\s+write_json\s*\(/u);
    const dumpMatch = nextSource.match(/\bjson\.dumps?\s*\(/u);
    const firstDumpIndex = dumpMatch?.index ?? -1;
    const precedingFunctionMatches =
      firstDumpIndex >= 0
        ? [...nextSource.slice(0, firstDumpIndex).matchAll(/\ndef\s+\w+\s*\(/gu)]
        : [];
    const enclosingFunctionIndex = precedingFunctionMatches.at(-1)?.index;
    const insertionIndex = writeJsonMatch?.index ?? enclosingFunctionIndex ?? (firstDumpIndex >= 0 ? firstDumpIndex : -1);
    if (insertionIndex < 0) {
      return { repaired: false };
    }
    nextSource = `${nextSource.slice(0, insertionIndex)}${helper}${nextSource.slice(insertionIndex)}`;
  }

  const lines = nextSource.split(/\r?\n/u);
  let changedDump = false;
  const repairedLines = lines.map((line) => {
    if (!/\bjson\.dumps?\s*\(/u.test(line)) {
      return line;
    }
    let repaired = wrapPythonJsonFirstArgumentWithAutolabosSafe(line);
    if (!/\ballow_nan\s*=/u.test(repaired) && /\bjson\.dump\s*\(/u.test(repaired) && /\)\s*$/u.test(repaired)) {
      repaired = repaired.replace(/\)\s*$/u, ", allow_nan=False)");
    }
    if (repaired !== line) {
      changedDump = true;
    }
    return repaired;
  });
  nextSource = repairedLines.join("\n");

  if ((!changedDump && !strengthenedJsonSafe) || nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Made metrics JSON serialization strict and non-finite-safe in ${path.basename(scriptPath)} before handoff.`
  };
}

interface PythonTopLevelFunctionDefinition {
  name: string;
  signature: string;
  startOffset: number;
  endOffset: number;
}

function collectPythonTopLevelFunctionDefinitions(source: string): PythonTopLevelFunctionDefinition[] {
  const lines = source.split("\n");
  const offsets: number[] = [];
  let offset = 0;
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index] || "";
    offsets.push(offset);
    offset += line.length + (index < lines.length - 1 ? 1 : 0);
  }

  const definitions: PythonTopLevelFunctionDefinition[] = [];
  for (let index = 0; index < lines.length; index += 1) {
    const line = lines[index] || "";
    const match = /^def\s+([A-Za-z_][A-Za-z0-9_]*)\s*\(/u.exec(line);
    if (!match) {
      continue;
    }

    let signatureEndLine = index;
    let signatureDepth = 0;
    for (let cursor = index; cursor < lines.length; cursor += 1) {
      const candidateLine = lines[cursor] || "";
      signatureDepth += countOccurrences(candidateLine, "(") - countOccurrences(candidateLine, ")");
      if (cursor > index && signatureDepth <= 0) {
        signatureEndLine = cursor;
        break;
      }
    }

    let functionEndLine = lines.length;
    for (let cursor = signatureEndLine + 1; cursor < lines.length; cursor += 1) {
      const candidateLine = lines[cursor] || "";
      const trimmed = candidateLine.trim();
      if (trimmed.length === 0 || trimmed.startsWith("#")) {
        continue;
      }
      if (!candidateLine.startsWith(" ") && !candidateLine.startsWith("\t")) {
        functionEndLine = cursor;
        break;
      }
    }

    const startOffset = offsets[index] ?? 0;
    const endOffset = offsets[functionEndLine] ?? source.length;
    const signature = extractPythonFunctionSignature(source.slice(startOffset, endOffset), match[1]) || "";
    definitions.push({ name: match[1], signature, startOffset, endOffset });
  }
  return definitions;
}

function pythonSignatureAcceptsVarKwargs(signature: string): boolean {
  return splitPythonSignatureParameters(signature)
    .map((param) => param.replace(/#.*/u, "").trim())
    .some((param) => /^\*\*\s*[A-Za-z_][A-Za-z0-9_]*(?:\s*:|\s*$|\s*=)/u.test(param));
}

function pythonSignatureAcceptsVarArgs(signature: string): boolean {
  return splitPythonSignatureParameters(signature)
    .map((param) => param.replace(/#.*/u, "").trim())
    .some((param) => /^\*(?!\*)\s*[A-Za-z_][A-Za-z0-9_]*(?:\s*:|\s*$|\s*=)/u.test(param));
}

function pythonSignaturePositionalCapacity(signature: string): number {
  if (pythonSignatureAcceptsVarArgs(signature)) {
    return Number.POSITIVE_INFINITY;
  }
  let count = 0;
  for (const rawParam of splitPythonSignatureParameters(signature)) {
    const param = rawParam.replace(/#.*/u, "").trim();
    if (!param || param === "/") {
      continue;
    }
    if (param === "*" || param.startsWith("*")) {
      break;
    }
    count += 1;
  }
  return count;
}

interface PythonCallShape {
  keywords: Set<string>;
  maxPositionalArgs: number;
}

function extractPythonCallShape(source: string, functionName: string): PythonCallShape {
  const keywords = new Set<string>();
  let maxPositionalArgs = 0;
  const escaped = escapeRegex(functionName);
  const pattern = new RegExp("\\b" + escaped + "\\s*\\(", "gu");
  for (const match of source.matchAll(pattern)) {
    if (match.index == null) {
      continue;
    }
    const prefix = source.slice(Math.max(0, match.index - 8), match.index);
    if (/\bdef\s*$/u.test(prefix)) {
      continue;
    }
    const openIndex = source.indexOf("(", match.index);
    if (openIndex < 0) {
      continue;
    }
    let depth = 0;
    let quote: "'" | "\"" | undefined;
    let escapedChar = false;
    let closeIndex = -1;
    for (let cursor = openIndex; cursor < source.length && cursor - openIndex < 3000; cursor += 1) {
      const char = source[cursor];
      if (quote) {
        if (escapedChar) {
          escapedChar = false;
        } else if (char === "\\") {
          escapedChar = true;
        } else if (char === quote) {
          quote = undefined;
        }
        continue;
      }
      if (char === "'" || char === "\"") {
        quote = char;
        continue;
      }
      if (char === "(") {
        depth += 1;
        continue;
      }
      if (char === ")") {
        depth -= 1;
        if (depth === 0) {
          closeIndex = cursor;
          break;
        }
      }
    }
    if (closeIndex < 0) {
      continue;
    }
    const callBody = source.slice(openIndex + 1, closeIndex);
    let positionalCount = 0;
    for (const rawArg of splitPythonSignatureParameters(callBody)) {
      const arg = rawArg.replace(/#.*/u, "").trim();
      if (!arg) {
        continue;
      }
      const keywordMatch = /^([A-Za-z_][A-Za-z0-9_]*)\s*=/u.exec(arg);
      if (keywordMatch) {
        keywords.add(keywordMatch[1]);
        continue;
      }
      if (!arg.startsWith("*")) {
        positionalCount += 1;
      }
    }
    maxPositionalArgs = Math.max(maxPositionalArgs, positionalCount);
  }
  return { keywords, maxPositionalArgs };
}

export async function repairPythonDuplicateHelperSignatureDriftSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  const definitions = collectPythonTopLevelFunctionDefinitions(source);
  const byName = new Map<string, PythonTopLevelFunctionDefinition[]>();
  for (const definition of definitions) {
    const group = byName.get(definition.name) || [];
    group.push(definition);
    byName.set(definition.name, group);
  }

  const rangesToRemove: Array<{ startOffset: number; endOffset: number; name: string }> = [];
  for (const [name, group] of byName.entries()) {
    if (group.length < 2) {
      continue;
    }
    const callShape = extractPythonCallShape(source, name);
    if (callShape.keywords.size === 0 && callShape.maxPositionalArgs === 0) {
      continue;
    }
    const finalDefinition = group[group.length - 1];
    const finalParams = new Set(extractPythonParameterNames(finalDefinition.signature));
    const finalAcceptsKwargs = pythonSignatureAcceptsVarKwargs(finalDefinition.signature);
    const finalPositionalCapacity = pythonSignaturePositionalCapacity(finalDefinition.signature);
    if (finalAcceptsKwargs && finalPositionalCapacity >= callShape.maxPositionalArgs) {
      continue;
    }

    const compatibleEarlierDefinition = [...group]
      .slice(0, -1)
      .reverse()
      .find((definition) => {
        const params = new Set(extractPythonParameterNames(definition.signature));
        const acceptsKwargs = pythonSignatureAcceptsVarKwargs(definition.signature);
        const positionalCapacity = pythonSignaturePositionalCapacity(definition.signature);
        const supportsKeywordCalls = [...callShape.keywords].some(
          (keyword) => !finalParams.has(keyword) && (acceptsKwargs || params.has(keyword))
        );
        const supportsPositionalCalls =
          callShape.maxPositionalArgs > finalPositionalCapacity && positionalCapacity >= callShape.maxPositionalArgs;
        return supportsKeywordCalls || supportsPositionalCalls;
      });
    if (!compatibleEarlierDefinition) {
      continue;
    }
    rangesToRemove.push({
      startOffset: finalDefinition.startOffset,
      endOffset: finalDefinition.endOffset,
      name
    });
  }

  if (rangesToRemove.length === 0) {
    return { repaired: false };
  }

  let nextSource = source;
  for (const range of rangesToRemove.sort((left, right) => right.startOffset - left.startOffset)) {
    nextSource = nextSource.slice(0, range.startOffset) + nextSource.slice(range.endOffset);
  }
  nextSource = nextSource.replace(/\n{4,}/gu, "\n\n\n");
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  const repairedNames = Array.from(new Set(rangesToRemove.map((range) => range.name))).sort();
  return {
    repaired: true,
    message: "Removed narrower duplicate helper definition(s) before handoff: " + repairedNames.join(", ") + "."
  };
}

function extractPythonStringListAssignment(lines: string[], variableName: string): string[] | undefined {
  const escapedName = escapeRegex(variableName);
  const startPattern = new RegExp(`\\b${escapedName}\\s*=\\s*\\[`, "u");
  for (let index = 0; index < lines.length; index += 1) {
    if (!startPattern.test(lines[index])) {
      continue;
    }
    const collected: string[] = [];
    let bracketDepth = 0;
    for (let cursor = index; cursor < lines.length; cursor += 1) {
      const line = lines[cursor];
      collected.push(line);
      bracketDepth += countOccurrences(line, "[") - countOccurrences(line, "]");
      if (bracketDepth <= 0) {
        const values = [...collected.join("\n").matchAll(/["']([^"'\\]+)["']/gu)].map((match) => match[1]);
        return values.length > 0 ? values : undefined;
      }
    }
  }
  return undefined;
}

function extractPythonDictWriterFieldnames(lines: string[]): string[] | undefined {
  const seen = new Set<string>();
  for (const line of lines) {
    for (const match of line.matchAll(/\bcsv\.DictWriter\s*\([^)]*fieldnames\s*=\s*([A-Za-z_][A-Za-z0-9_]*)/gu)) {
      const variableName = match[1];
      if (seen.has(variableName)) {
        continue;
      }
      seen.add(variableName);
      const values = extractPythonStringListAssignment(lines, variableName);
      if (values && values.length > 0) {
        return values;
      }
    }
  }
  return extractPythonStringListAssignment(lines, "fieldnames");
}

function extractConfigPathFromCommand(command?: string, cwd?: string): string | undefined {
  if (!command) {
    return undefined;
  }
  const match = command.match(/\s--config(?:\s+|=)(?:"([^"]+)"|'([^']+)'|(\S+))/u);
  const raw = match?.[1] || match?.[2] || match?.[3];
  if (!raw) {
    return undefined;
  }
  const candidate = raw.trim();
  if (!candidate) {
    return undefined;
  }
  if (path.isAbsolute(candidate)) {
    return candidate;
  }
  return path.resolve(cwd || process.cwd(), candidate);
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
}

function firstPresentRecordString(record: Record<string, unknown>, keys: string[]): string | undefined {
  for (const key of keys) {
    const value = record[key];
    if (typeof value === "string" && value.trim()) {
      return value.trim();
    }
  }
  return undefined;
}

function firstPresentRecordNumber(record: Record<string, unknown>, keys: string[]): number | undefined {
  for (const key of keys) {
    const value = record[key];
    if (typeof value === "number" && Number.isFinite(value)) {
      return value;
    }
  }
  return undefined;
}

function firstPresentRecordBoolean(record: Record<string, unknown>, keys: string[]): boolean | undefined {
  for (const key of keys) {
    const value = record[key];
    if (typeof value === "boolean") {
      return value;
    }
  }
  return undefined;
}

function firstPresentStringArray(record: Record<string, unknown>, keys: string[]): string[] | undefined {
  for (const key of keys) {
    const value = record[key];
    if (Array.isArray(value)) {
      const normalized = value
        .filter((item): item is string => typeof item === "string")
        .map((item) => item.trim())
        .filter(Boolean);
      if (normalized.length > 0) {
        return normalized;
      }
    }
  }
  return undefined;
}

function normalizeLockedRecipeName(rawName: string, seenNames: Set<string>): string {
  const base = rawName.trim() || "recipe";
  if (!seenNames.has(base)) {
    seenNames.add(base);
    return base;
  }
  let suffix = 2;
  while (seenNames.has(`${base}_${suffix}`)) {
    suffix += 1;
  }
  const next = `${base}_${suffix}`;
  seenNames.add(next);
  return next;
}

export function normalizeLockedPeftStudyConfigPayloadForCompatibility(
  rawPayload: unknown
): { repaired: boolean; payload?: Record<string, unknown>; message?: string } {
  if (!isPlainObject(rawPayload)) {
    return { repaired: false };
  }
  const payload: Record<string, unknown> = { ...rawPayload };
  const rawConditions = Array.isArray(payload.conditions) ? payload.conditions : undefined;
  if (!rawConditions || rawConditions.length === 0) {
    return { repaired: false, payload };
  }

  const loading = isPlainObject(payload.loading) ? payload.loading : undefined;
  const defaultQuantization =
    firstPresentRecordString(loading || {}, ["quantization", "quantization_mode"]) ||
    (firstPresentRecordBoolean(loading || {}, ["load_in_4bit", "use_quantization_for_tuned_runs"])
      ? "4bit"
      : undefined);

  const recipes: Array<Record<string, unknown>> = [];
  const seenNames = new Set<string>();
  let droppedBaseline = false;
  let changed = false;

  for (const item of rawConditions) {
    if (!isPlainObject(item)) {
      continue;
    }
    const isBaseline =
      firstPresentRecordBoolean(item, ["baseline", "is_baseline"]) === true ||
      ["baseline"].includes(
        (firstPresentRecordString(item, ["kind", "recipe_type", "type", "adapter_type"]) || "").toLowerCase()
      ) ||
      (firstPresentRecordBoolean(item, ["evaluate_only"]) === true &&
        firstPresentRecordBoolean(item, ["train"]) === false);
    if (isBaseline) {
      droppedBaseline = true;
      changed = true;
      continue;
    }
    const requestedAdapterType =
      firstPresentRecordString(item, ["adapter_type", "recipe_type", "type", "peft_method", "peft_type"]) ||
      (firstPresentRecordBoolean(item, ["use_decomposed_adapter"]) ? "decomposed_adapter" : undefined) ||
      "adapter";
    const normalizedAdapterType =
      requestedAdapterType.toLowerCase() === "peft" ? "adapter" : requestedAdapterType.toLowerCase();

    const recipe: Record<string, unknown> = {
      name: normalizeLockedRecipeName(
        firstPresentRecordString(item, ["name", "label", "id", "recipe_name", "condition_name"]) || "recipe",
        seenNames
      ),
      adapter_type: normalizedAdapterType,
      enabled: firstPresentRecordBoolean(item, ["enabled"]) ?? true
    };
    const r = firstPresentRecordNumber(item, ["r", "adapter_r", "rank"]);
    if (r !== undefined) {
      recipe.r = r;
    }
    const alpha = firstPresentRecordNumber(item, ["adapter_alpha", "alpha"]);
    if (alpha !== undefined) {
      recipe.adapter_alpha = alpha;
    }
    const dropout = firstPresentRecordNumber(item, ["adapter_dropout", "dropout"]);
    if (dropout !== undefined) {
      recipe.adapter_dropout = dropout;
    }
    const targetModules = firstPresentStringArray(item, ["target_modules"]);
    if (targetModules && targetModules.length > 0) {
      recipe.target_modules = targetModules;
    }
    const quantization =
      firstPresentRecordString(item, ["quantization", "quantization_mode"]) || defaultQuantization;
    if (quantization) {
      recipe.quantization = quantization.toLowerCase();
    }
    if (normalizedAdapterType === "decomposed_adapter") {
      recipe.use_decomposed_adapter = true;
    }
    recipes.push(recipe);
    changed = true;
  }

  if (!changed || recipes.length === 0) {
    return { repaired: false, payload };
  }

  payload.recipes = recipes;
  delete payload.conditions;
  if (payload.require_baseline_first === undefined) {
    payload.require_baseline_first =
      firstPresentRecordBoolean(payload, ["baseline_first_required", "require_baseline_first"]) ?? true;
  }
  if (payload.study_name === undefined) {
    const derivedStudyName =
      firstPresentRecordString(payload, ["study_name", "experiment_name", "run_id"]) ||
      "locked_adapter_instruction_study";
    payload.study_name = derivedStudyName;
  }

  return {
    repaired: true,
    payload,
    message: droppedBaseline
      ? "Normalized locked adapter config to recipes-only schema and removed the baseline entry before handoff."
      : "Normalized locked adapter config to the recipes-only runtime schema before handoff."
  };
}

export async function repairLockedPeftStudyConfigSurface(configPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!configPath) {
    return { repaired: false };
  }

  const ext = path.extname(configPath).toLowerCase();
  if (![".yaml", ".yml", ".json"].includes(ext)) {
    return { repaired: false };
  }

  let raw: string;
  try {
    raw = await fs.readFile(configPath, "utf8");
  } catch {
    return { repaired: false };
  }

  let parsed: unknown;
  try {
    parsed = ext === ".json" ? JSON.parse(raw) : YAML.parse(raw);
  } catch {
    return { repaired: false };
  }

  const normalized = normalizeLockedPeftStudyConfigPayloadForCompatibility(parsed);
  if (!normalized.repaired || !normalized.payload) {
    return { repaired: false };
  }

  const nextRaw =
    ext === ".json"
      ? `${JSON.stringify(normalized.payload, null, 2)}\n`
      : YAML.stringify(normalized.payload, { indent: 2 });
  if (nextRaw === raw) {
    return { repaired: false };
  }
  await fs.writeFile(configPath, nextRaw, "utf8");
  return {
    repaired: true,
    message: normalized.message || `Normalized ${path.basename(configPath)} to the locked-study runtime schema.`
  };
}

export async function repairPythonLockedConditionCountSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  const exactCheck =
    "    if len(resolved_conditions) != LOCKED_CONDITION_COUNT:\n" +
    "        raise ConfigError(\n" +
    "            f'The locked comparison requires exactly {LOCKED_CONDITION_COUNT} tuned conditions, '\n" +
    "            f'but resolved {len(resolved_conditions)}.'\n" +
    "        )";
  if (!source.includes(exactCheck)) {
    return { repaired: false };
  }

  const replacement =
    "    require_baseline_first = _bool_or(_cfg_get(config, 'require_baseline_first', 'baseline_first_required', default=True), True)\n" +
    "    expected_tuned_conditions = LOCKED_CONDITION_COUNT - (1 if require_baseline_first else 0)\n" +
    "    if len(resolved_conditions) != expected_tuned_conditions:\n" +
    "        raise ConfigError(\n" +
    "            f'The locked comparison requires exactly {expected_tuned_conditions} tuned conditions, '\n" +
    "            f'but resolved {len(resolved_conditions)}.'\n" +
    "        )";

  const nextSource = source.replace(exactCheck, replacement);
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Aligned locked-condition counting in ${path.basename(scriptPath)} with baseline-first adapter studies before handoff.`
  };
}

export async function repairPythonConditionHelperSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  if (source.includes("run_root=runs_dir") || !source.includes("def _execute_condition_via_helper(")) {
    return { repaired: false };
  }

  const needle =
    "        public_dir=public_dir,\n" +
    "        output_dir=run_dir,\n" +
    "        run_dir=run_dir,\n" +
    "        artifact_dir=run_dir,\n" +
    "        artifacts_dir=run_dir,\n" +
    "        timeout_sec=timeout_sec,\n";
  if (!source.includes(needle)) {
    return { repaired: false };
  }

  const replacement =
    "        public_dir=public_dir,\n" +
    "        output_dir=run_dir,\n" +
    "        run_dir=run_dir,\n" +
    "        run_root=runs_dir,\n" +
    "        artifact_dir=run_dir,\n" +
    "        artifacts_dir=run_dir,\n" +
    "        deadline_monotonic=(time.monotonic() + float(timeout_sec) if timeout_sec is not None else None),\n" +
    "        timeout_sec=timeout_sec,\n";

  const nextSource = source.replace(needle, replacement);
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Aligned condition-helper invocation kwargs in ${path.basename(scriptPath)} before handoff.`
  };
}

export async function repairPythonLockedSweepRuntimeKwargBridgeSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  const marker = "_autolabos_locked_sweep_runtime_kwarg_bridge_marker";
  if (
    !source.includes("def _run_locked_baseline_first_sweep_impl(") ||
    !source.includes("def _invoke_helper(") ||
    !source.includes("raw_condition_results") ||
    !source.includes("execution_kwargs.update(")
  ) {
    return { repaired: false };
  }

  let repaired = false;
  let nextSource = source;

  const helperKwargNeedle = '            "run_name": args.run_name,\n';
  if (nextSource.includes(helperKwargNeedle) && !nextSource.includes('"base_model_id": getattr(args, "preferred_model_id", None),')) {
    nextSource = nextSource.replace(
      helperKwargNeedle,
      helperKwargNeedle +
        '            "model_id": getattr(args, "preferred_model_id", None),\n' +
        '            "base_model_id": getattr(args, "preferred_model_id", None),\n' +
        '            "selected_model_id": getattr(args, "preferred_model_id", None),\n'
    );
    repaired = true;
  }

  const conditionKwargNeedle = '                        "condition": condition,\n';
  if (nextSource.includes(conditionKwargNeedle) && !nextSource.includes('"train_data": context.get("train_data")')) {
    nextSource = nextSource.replace(
      conditionKwargNeedle,
      conditionKwargNeedle +
        '                        "model_id": context.get("model_id") or context.get("selected_model_id") or context.get("resolved_model_id") or context.get("base_model_id"),\n' +
        '                        "base_model_id": context.get("base_model_id") or context.get("model_id") or context.get("selected_model_id"),\n' +
        '                        "selected_model_id": context.get("selected_model_id") or context.get("model_id") or context.get("base_model_id"),\n' +
        '                        "train_data": context.get("train_data") or context.get("train_dataset"),\n' +
        '                        "task_a_data": context.get("task_a_data") or _coerce_mapping(context.get("eval_datasets")).get("benchmark_task_a"),\n' +
        '                        "task_b_data": context.get("task_b_data") or _coerce_mapping(context.get("eval_datasets")).get("benchmark_task_b"),\n'
    );
    repaired = true;
  }

  const orchestrationNeedle = '        orchestration_helper = _resolve_callable(\n';
  if (
    nextSource.includes(orchestrationNeedle) &&
    nextSource.includes("def load_instruction_tuning_examples(") &&
    nextSource.includes("def load_evaluation_examples_bundle(") &&
    !nextSource.includes(`# ${marker}`)
  ) {
    const materializationBlock = [
      `        # ${marker}`,
      `        if callable(globals().get("load_instruction_tuning_examples")) and "train_data" not in run_context:`,
      `            _autolabos_train_data, _autolabos_train_meta = load_instruction_tuning_examples(`,
      `                max_samples=getattr(args, "max_train_samples", globals().get("DEFAULT_MAX_TRAIN_SAMPLES", 0)),`,
      `                seed=getattr(args, "seed", globals().get("DEFAULT_SEED", 0)),`,
      `                cache_dir=getattr(args, "cache_dir", globals().get("DEFAULT_CACHE_DIR", None)),`,
      `            )`,
      `            run_context["train_data"] = [`,
      `                dict(vars(item)) if hasattr(item, "__dict__") else item`,
      `                for item in _autolabos_train_data`,
      `            ]`,
      `            run_context["train_dataset"] = run_context["train_data"]`,
      `            run_context.setdefault("dataset_metadata", {})["train"] = _autolabos_train_meta`,
      `        if callable(globals().get("load_evaluation_examples_bundle")) and "eval_datasets" not in run_context:`,
      `            _autolabos_eval_datasets, _autolabos_eval_meta = load_evaluation_examples_bundle(`,
      `                max_samples=getattr(args, "max_eval_samples", globals().get("DEFAULT_MAX_EVAL_SAMPLES", 0)),`,
      `                seed=getattr(args, "seed", globals().get("DEFAULT_SEED", 0)),`,
      `                cache_dir=getattr(args, "cache_dir", globals().get("DEFAULT_CACHE_DIR", None)),`,
      `            )`,
      `            run_context["eval_datasets"] = _autolabos_eval_datasets`,
      `            if hasattr(_autolabos_eval_datasets, "get"):`,
      `                run_context["task_a_data"] = _autolabos_eval_datasets.get("benchmark_task_a")`,
      `                run_context["task_b_data"] = _autolabos_eval_datasets.get("benchmark_task_b")`,
      `            run_context.setdefault("dataset_metadata", {})["eval"] = _autolabos_eval_meta`,
      `        _autolabos_model_id = (`,
      `            run_context.get("selected_model_id")`,
      `            or run_context.get("model_id")`,
      `            or getattr(args, "preferred_model_id", None)`,
      `            or getattr(args, "model_id", None)`,
      `            or globals().get("PREFERRED_MODEL_ID")`,
      `        )`,
      `        if _autolabos_model_id is not None:`,
      `            run_context["model_id"] = _autolabos_model_id`,
      `            run_context.setdefault("base_model_id", _autolabos_model_id)`,
      `            run_context.setdefault("selected_model_id", _autolabos_model_id)`,
      `        helper_kwargs.update({`,
      `            "model_id": run_context.get("model_id"),`,
      `            "base_model_id": run_context.get("base_model_id"),`,
      `            "selected_model_id": run_context.get("selected_model_id"),`,
      `            "train_data": run_context.get("train_data"),`,
      `            "train_dataset": run_context.get("train_dataset"),`,
      `            "eval_datasets": run_context.get("eval_datasets"),`,
      `            "task_a_data": run_context.get("task_a_data"),`,
      `            "task_b_data": run_context.get("task_b_data"),`,
      `        })`,
      ``
    ].join("\n");
    nextSource = nextSource.replace(orchestrationNeedle, `${materializationBlock}${orchestrationNeedle}`);
    repaired = true;
  }

  const reportingNeedle = '            "raw_results": raw_results,\n';
  const reportingKwargsAlreadyBridged =
    /\breporting_kwargs\s*:\s*JSONDict\s*=\s*\{[\s\S]{0,700}"raw_condition_results"\s*:\s*raw_results/u.test(
      nextSource
    );
  if (nextSource.includes(reportingNeedle) && !reportingKwargsAlreadyBridged) {
    nextSource = nextSource.replace(
      reportingNeedle,
      reportingNeedle +
        '            "raw_condition_results": (raw_results.get("condition_results") if isinstance(raw_results, dict) and isinstance(raw_results.get("condition_results"), list) else raw_results),\n' +
        '            "condition_results": (raw_results.get("condition_results") if isinstance(raw_results, dict) and isinstance(raw_results.get("condition_results"), list) else raw_results),\n' +
        '            "preflight_summary": preflight_result,\n' +
        '            "selected_model_id": run_context.get("selected_model_id") or run_context.get("model_id"),\n' +
        '            "study_start_time": started_at,\n' +
        '            "study_end_time": time.time(),\n' +
        '            "run_command": runnable_command,\n'
    );
    repaired = true;
  }

  const directSummaryRawReportingPattern =
    /(\breporting_kwargs\s*:\s*JSONDict\s*=\s*\{[\s\S]{0,700})(\s*)"raw_condition_results"\s*:\s*raw_results,\n\s*"condition_results"\s*:\s*raw_results,/u;
  if (directSummaryRawReportingPattern.test(nextSource)) {
    nextSource = nextSource.replace(
      directSummaryRawReportingPattern,
      (_match, prefix: string, indent: string) =>
        `${prefix}${indent}"raw_condition_results": (raw_results.get("condition_results") if isinstance(raw_results, dict) and isinstance(raw_results.get("condition_results"), list) else raw_results),\n` +
        `${indent}"condition_results": (raw_results.get("condition_results") if isinstance(raw_results, dict) and isinstance(raw_results.get("condition_results"), list) else raw_results),`
    );
    repaired = true;
  }

  if (!repaired || nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Bridged locked-sweep runtime data/model and metrics kwargs in ${path.basename(scriptPath)} before handoff.`
  };
}

export async function repairPythonPlannedConditionContractSurface(
  scriptPath?: string,
  contract?: PlannedConditionImplementationContract
): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py" || !contract) {
    return { repaired: false };
  }

  const requiredMarkers = dedupeStrings(contract.required_condition_markers || []);
  const seedSchedule = (contract.seed_schedule || [])
    .map((seed) => Number(seed))
    .filter((seed) => Number.isInteger(seed));
  const requiredConditionCount = normalizeContractPositiveInteger(contract.required_condition_count);
  const requiredRunCount = normalizeContractPositiveInteger(contract.required_run_count);
  if (
    requiredMarkers.length === 0 &&
    seedSchedule.length === 0 &&
    requiredConditionCount === undefined &&
    requiredRunCount === undefined
  ) {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  const block = buildPythonPlannedConditionContractBlock({
    requiredMarkers,
    baselineMarker: contract.baseline_condition_marker,
    seedSchedule,
    requiredConditionCount,
    requiredRunCount
  });
  const existingBlockPattern = /\n?# _autolabos_planned_condition_contract_marker_start\n[\s\S]*?# _autolabos_planned_condition_contract_marker_end\n?/u;
  const nextSource = existingBlockPattern.test(source)
    ? source.replace(existingBlockPattern, `\n${block}\n`)
    : insertPythonContractBlockBeforePublicDeclarations(source, block);
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Materialized the planned condition/seed contract in ${path.basename(scriptPath)} before design validation.`
  };
}

export async function materializePublicPlannedConditionContractArtifact(input: {
  publicDir?: string;
  contract?: PlannedConditionImplementationContract;
}): Promise<{ repaired: boolean; artifactPath?: string; message?: string }> {
  if (!input.publicDir || !input.contract) {
    return { repaired: false };
  }

  const requiredMarkers = dedupeStrings(input.contract.required_condition_markers || []);
  const seedSchedule = (input.contract.seed_schedule || [])
    .map((seed) => Number(seed))
    .filter((seed) => Number.isInteger(seed));
  const requiredConditionCount = normalizeContractPositiveInteger(input.contract.required_condition_count);
  const requiredRunCount = normalizeContractPositiveInteger(input.contract.required_run_count);
  if (
    requiredMarkers.length === 0 &&
    seedSchedule.length === 0 &&
    requiredConditionCount === undefined &&
    requiredRunCount === undefined
  ) {
    return { repaired: false };
  }

  const artifactPath = path.join(input.publicDir, "locked_condition_contract.json");
  const payload = {
    version: 1,
    source: "approved_design_contract",
    required_condition_markers: requiredMarkers,
    baseline_condition_marker: input.contract.baseline_condition_marker || requiredMarkers[0] || null,
    required_condition_count: requiredConditionCount ?? requiredMarkers.length,
    seed_schedule: seedSchedule,
    required_run_count:
      requiredRunCount ??
      (requiredMarkers.length > 0 && seedSchedule.length > 0
        ? requiredMarkers.length * seedSchedule.length
        : null)
  };

  let previous = "";
  try {
    previous = await fs.readFile(artifactPath, "utf8");
  } catch {
    previous = "";
  }
  const next = `${JSON.stringify(payload, null, 2)}\n`;
  if (previous === next) {
    return { repaired: false, artifactPath };
  }

  await writeJsonFile(artifactPath, payload);
  return {
    repaired: true,
    artifactPath,
    message: `Materialized public planned condition contract artifact in ${path.basename(artifactPath)} before design validation.`
  };
}

function buildPythonPlannedConditionContractBlock(params: {
  requiredMarkers: string[];
  baselineMarker?: string;
  seedSchedule: number[];
  requiredConditionCount?: number;
  requiredRunCount?: number;
}): string {
  const conditionCount = params.requiredConditionCount ?? params.requiredMarkers.length;
  const runCount =
    params.requiredRunCount ??
    (params.requiredMarkers.length > 0 && params.seedSchedule.length > 0
      ? params.requiredMarkers.length * params.seedSchedule.length
      : undefined);
  const lines = [
    "# _autolabos_planned_condition_contract_marker_start",
    "# AutoLabOS materializes the approved design contract for static handoff validation.",
    `PLANNED_CONDITION_MARKERS = ${toPythonTupleLiteral(params.requiredMarkers)}`
  ];
  if (params.baselineMarker) {
    lines.push(`BASELINE_CONDITION_MARKER = ${JSON.stringify(params.baselineMarker)}`);
  }
  if (conditionCount !== undefined) {
    lines.push(`REQUIRED_CONDITION_COUNT = ${conditionCount}`);
  }
  if (params.seedSchedule.length > 0) {
    lines.push(`PLANNED_SEEDS = ${toPythonTupleLiteral(params.seedSchedule)}`);
    lines.push("SEED_SCHEDULE = PLANNED_SEEDS");
  }
  if (runCount !== undefined) {
    lines.push(`REQUIRED_RUN_COUNT = ${runCount}`);
    lines.push(`PLANNED_RUN_COUNT = ${runCount}`);
  }
  if (params.requiredMarkers.length > 0) {
    lines.push(
      "PLANNED_CONDITIONS = [",
      "    {'condition_marker': marker, 'marker': marker, 'condition_id': marker, 'name': marker}",
      "    for marker in PLANNED_CONDITION_MARKERS",
      "]"
    );
  }
  if (params.requiredMarkers.length > 0 && params.seedSchedule.length > 0) {
    lines.push(
      "PLANNED_CONDITION_SEED_RUNS = [",
      "    {'condition_marker': marker, 'marker': marker, 'condition_id': marker, 'seed': seed}",
      "    for marker in PLANNED_CONDITION_MARKERS",
      "    for seed in PLANNED_SEEDS",
      "]"
    );
  }
  lines.push("# _autolabos_planned_condition_contract_marker_end", "");
  return lines.join("\n");
}

function toPythonTupleLiteral(values: Array<string | number>): string {
  if (values.length === 0) {
    return "()";
  }
  const renderedValues = values.map((value) => JSON.stringify(value));
  const suffix = renderedValues.length === 1 ? "," : "";
  return `(${renderedValues.join(", ")}${suffix})`;
}

function normalizeContractPositiveInteger(value: unknown): number | undefined {
  const parsed = typeof value === "number" ? value : Number(value);
  if (!Number.isFinite(parsed) || parsed <= 0) {
    return undefined;
  }
  return Math.floor(parsed);
}

function insertPythonContractBlockBeforePublicDeclarations(source: string, block: string): string {
  const lines = source.split(/\n/u);
  let index = 0;
  if (lines[index]?.startsWith("#!")) {
    index += 1;
  }
  while (
    index < lines.length &&
    (/^#.*coding[:=]/iu.test(lines[index] || "") || (lines[index] || "").trim() === "")
  ) {
    index += 1;
  }

  const firstMeaningfulLine = lines[index] || "";
  const docstringDelimiter = firstMeaningfulLine.trim().match(/^(?:[rRuUbBfF]+)?(["']{3})/u)?.[1];
  if (docstringDelimiter) {
    index += 1;
    while (index < lines.length && !(lines[index] || "").includes(docstringDelimiter)) {
      index += 1;
    }
    if (index < lines.length) {
      index += 1;
    }
  }

  while (index < lines.length && (lines[index] || "").trim() === "") {
    index += 1;
  }
  while (index < lines.length && /^from\s+__future__\s+import\s+/u.test(lines[index] || "")) {
    index += 1;
    while (index < lines.length && (lines[index] || "").trim() === "") {
      index += 1;
    }
  }
  while (index < lines.length && /^(?:import\s+|from\s+)/u.test(lines[index] || "")) {
    index += 1;
    while (
      index < lines.length &&
      /^\s*(?:\)|,|[A-Za-z_][A-Za-z0-9_]*\s*,?\s*)$/u.test(lines[index] || "")
    ) {
      index += 1;
    }
    while (index < lines.length && (lines[index] || "").trim() === "") {
      index += 1;
    }
  }

  const before = lines.slice(0, index).join("\n");
  const after = lines.slice(index).join("\n");
  const prefix = before.length > 0 ? `${before}\n\n` : "";
  return `${prefix}${block}${after}`;
}

export async function repairPythonConditionSeedPlanDispatchSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  let repaired = false;
  let nextSource = source;

  const executeNamesNeedle =
    '            "_run_condition_seed_plan",\n' +
    '            "run_condition_seed_plan",\n';
  if (
    nextSource.includes("def _execute_plan_bundle_any(") &&
    nextSource.includes("def run_condition_seed_execution_loop(") &&
    nextSource.includes("def _run_single_condition_seed(") &&
    nextSource.includes('include_keywords=("condition", "seed")') &&
    nextSource.includes(executeNamesNeedle) &&
    !nextSource.includes('"run_condition_seed_execution_loop"')
  ) {
    nextSource = nextSource.replace(
      executeNamesNeedle,
      executeNamesNeedle +
        '            "run_condition_seed_execution_loop",\n' +
        '            "execute_condition_seed_loop",\n' +
        '            "_run_condition_seed_execution_loop",\n' +
        '            "_execute_condition_seed_loop",\n'
    );
    repaired = true;
  }

  const seedScheduleAnyNeedle =
    "                return [int(seed) for seed in list(plan_bundle[key])]\n";
  if (
    nextSource.includes("def _resolve_seed_schedule_any(") &&
    nextSource.includes(seedScheduleAnyNeedle) &&
    !nextSource.includes("raw_plan_seeds.replace(\";\", \",\")")
  ) {
    nextSource = nextSource.replace(
      seedScheduleAnyNeedle,
      [
        "                raw_plan_seeds = plan_bundle[key]",
        "                if isinstance(raw_plan_seeds, str):",
        "                    return [",
        "                        int(seed.strip())",
        "                        for seed in raw_plan_seeds.replace(\";\", \",\").split(\",\")",
        "                        if seed.strip()",
        "                    ]",
        "                return [int(seed) for seed in list(raw_plan_seeds)]",
        ""
      ].join("\n")
    );
    repaired = true;
  }

  const seedScheduleNeedle = "    seeds = [int(seed) for seed in list(raw_seeds)]\n";
  if (
    nextSource.includes("def _resolve_seed_schedule(") &&
    nextSource.includes(seedScheduleNeedle) &&
    !nextSource.includes("raw_seeds.replace(\";\", \",\")")
  ) {
    nextSource = nextSource.replace(
      seedScheduleNeedle,
      [
        "    if isinstance(raw_seeds, str):",
        "        seed_items = [",
        "            item.strip()",
        "            for item in raw_seeds.replace(\";\", \",\").split(\",\")",
        "            if item.strip()",
        "        ]",
        "    else:",
        "        seed_items = list(raw_seeds)",
        "    seeds = [int(seed) for seed in seed_items]",
        ""
      ].join("\n")
    );
    repaired = true;
  }

  if (!repaired || nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Preferred the generated condition/seed execution loop and hardened seed CSV parsing in ${path.basename(scriptPath)} before handoff.`
  };
}

export async function repairPythonWorkflowSingleRunExecutorCandidateSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  const marker = "_autolabos_workflow_single_run_executor_candidate_marker";
  const needle =
    '            "execute_single_planned_run",\n' +
    '            "run_single_planned_run",\n' +
    '            "execute_planned_run",\n' +
    '            "run_condition_seed",\n';
  if (
    source.includes(marker) ||
    !source.includes('raise RuntimeError("No experiment execution helper is available in the current runner.")') ||
    !source.includes(needle)
  ) {
    return { repaired: false };
  }

  const availableCandidates = [
    "execute_one_planned_run",
    "execute_condition_seed_run",
    "execute_condition_seed_experiment",
    "run_condition_seed_experiment",
    "run_one_condition_seed"
  ].filter((name) => pythonSourceDefinesOrImportsName(source, name));
  if (availableCandidates.length === 0) {
    return { repaired: false };
  }

  const insertion =
    `            # ${marker}\n` +
    availableCandidates.map((name) => `            ${JSON.stringify(name)},`).join("\n") +
    "\n";
  const nextSource = source.replace(needle, needle + insertion);
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Added generated single-run executor candidates (${availableCandidates.join(", ")}) to workflow fallback resolution in ${path.basename(scriptPath)} before handoff.`
  };
}

export async function repairPythonWorkflowConditionRowsFromPlannedRunsSurface(scriptPath?: string): Promise<{
  repaired: boolean;
  message?: string;
}> {
  if (!scriptPath || path.extname(scriptPath) !== ".py") {
    return { repaired: false };
  }

  let source: string;
  try {
    source = await fs.readFile(scriptPath, "utf8");
  } catch {
    return { repaired: false };
  }

  const marker = "_autolabos_condition_rows_from_planned_runs_marker";
  const needle = "    grouped_rows: Dict[str, List[Mapping[str, Any]]] = {}\n";
  if (
    source.includes(marker) ||
    !source.includes("def _workflow_fallback_aggregate(") ||
    !source.includes("condition_specs_raw = runtime_context.get(\"condition_specs\")") ||
    !source.includes("planned_run_rows: Sequence[Mapping[str, Any]]") ||
    !source.includes(needle)
  ) {
    return { repaired: false };
  }

  const block = [
    `    # ${marker}`,
    "    if not condition_rows:",
    "        seen_condition_markers = set()",
    "        for planned_row in planned_run_rows:",
    "            planned_mapping = _as_row_dict(planned_row)",
    "            condition_payload = planned_mapping.get(\"condition\") or planned_mapping.get(\"condition_spec\") or planned_mapping.get(\"spec\")",
    "            spec_row = _as_row_dict(condition_payload)",
    "            marker = (",
    "                spec_row.get(\"condition_marker\")",
    "                or spec_row.get(\"marker\")",
    "                or planned_mapping.get(\"condition_marker\")",
    "                or planned_mapping.get(\"marker\")",
    "            )",
    "            if marker is None:",
    "                continue",
    "            marker = str(marker)",
    "            if marker in seen_condition_markers:",
    "                continue",
    "            seen_condition_markers.add(marker)",
    "            if not spec_row:",
    "                spec_row = {}",
    "            spec_row[\"condition_marker\"] = marker",
    "            for key in (\"rank\", \"dropout\", \"adapter_dropout\", \"is_baseline\", \"baseline\"):",
    "                if spec_row.get(key) is None and planned_mapping.get(key) is not None:",
    "                    spec_row[key] = planned_mapping.get(key)",
    "            condition_rows.append(spec_row)",
    ""
  ].join("\n");
  const nextSource = source.replace(needle, block + needle);
  if (nextSource === source) {
    return { repaired: false };
  }

  await fs.writeFile(scriptPath, nextSource, "utf8");
  return {
    repaired: true,
    message: `Derived fallback condition summaries from planned run rows in ${path.basename(scriptPath)} before handoff.`
  };
}

